import { Card, Stack, Row, Text } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  currentTemp: number;
  condition: string;
  conditionIcon: string;
  humidity: number;
  windSpeed: number;
  tempUnit?: 'C' | 'F';
  windUnit?: 'mph' | 'kmh';
  forecast?: ForecastDay[];
}

const getWeatherEmoji = (icon: string): string => {
  const emojiMap: Record<string, string> = {
    'sunny': '☀️',
    'cloudy': '☁️',
    'rainy': '🌧️',
    'stormy': '⛈️',
    'snowy': '❄️',
    'windy': '💨',
    'foggy': '🌫️',
    'partly-cloudy': '⛅',
    'clear-night': '🌙',
    'heavy-rain': '🌧️',
    'sleet': '🌨️',
  };
  return emojiMap[icon] || '🌡️';
};

export default function GeneratedComponent({
  currentTemp,
  condition,
  conditionIcon,
  humidity,
  windSpeed,
  tempUnit = 'F',
  windUnit = 'mph',
  forecast = [],
}: Props) {
  return (
    <Card padding={24} shadow="md">
      <Stack direction="vertical" gap={24}>
        {/* Current Weather Section */}
        <Stack direction="vertical" gap={16} align="center">
          <div style={{ fontSize: '72px' }}>
            {getWeatherEmoji(conditionIcon)}
          </div>
          <div style={{ textAlign: 'center' }}>
            <Text variant="h1" style={{ 
              fontSize: 'var(--ggui-font-size-4xl, 36px)',
              color: 'var(--ggui-color-primary-600, #0284c7)',
              fontWeight: 'var(--ggui-font-weight-bold, 700)',
            }}>
              {currentTemp}°{tempUnit}
            </Text>
            <Text variant="body" color="var(--ggui-color-neutral-600, #4b5563)" style={{
              fontSize: 'var(--ggui-font-size-lg, 18px)',
              marginTop: 'var(--ggui-spacing-2, 8px)',
            }}>
              {condition}
            </Text>
          </div>
        </Stack>

        {/* Weather Details Section */}
        <Row gap={16} justify="around" align="center">
          <Stack direction="vertical" gap={8} align="center">
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" style={{
              fontSize: 'var(--ggui-font-size-xs, 12px)',
            }}>
              Humidity
            </Text>
            <Text style={{
              fontSize: 'var(--ggui-font-size-lg, 18px)',
              fontWeight: 'var(--ggui-font-weight-semibold, 600)',
              color: 'var(--ggui-color-neutral-900, #111827)',
            }}>
              {humidity}%
            </Text>
          </Stack>

          <Stack direction="vertical" gap={8} align="center">
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)" style={{
              fontSize: 'var(--ggui-font-size-xs, 12px)',
            }}>
              Wind Speed
            </Text>
            <Text style={{
              fontSize: 'var(--ggui-font-size-lg, 18px)',
              fontWeight: 'var(--ggui-font-weight-semibold, 600)',
              color: 'var(--ggui-color-neutral-900, #111827)',
            }}>
              {windSpeed} {windUnit}
            </Text>
          </Stack>
        </Row>

        {/* Divider */}
        <div style={{
          height: '1px',
          backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
        }} />

        {/* 5-Day Forecast */}
        {forecast.length > 0 && (
          <Stack direction="vertical" gap={12}>
            <Text variant="label" style={{
              fontSize: 'var(--ggui-font-size-sm, 14px)',
              fontWeight: 'var(--ggui-font-weight-semibold, 600)',
              color: 'var(--ggui-color-neutral-900, #111827)',
            }}>
              5-Day Forecast
            </Text>
            <Row gap={8} justify="between" wrap>
              {forecast.map((day, index) => (
                <div
                  key={index}
                  style={{
                    flex: '1 1 calc(20% - 6.4px)',
                    minWidth: '80px',
                    padding: 'var(--ggui-spacing-2, 8px)',
                    backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                    textAlign: 'center',
                    display: 'flex',
                    flexDirection: 'column',
                    gap: 'var(--ggui-spacing-2, 8px)',
                    alignItems: 'center',
                  }}
                >
                  <Text variant="caption" style={{
                    fontSize: 'var(--ggui-font-size-xs, 12px)',
                    fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                    color: 'var(--ggui-color-neutral-700, #374151)',
                  }}>
                    {day.day}
                  </Text>
                  <div style={{ fontSize: '28px' }}>
                    {getWeatherEmoji(day.icon)}
                  </div>
                  <Stack direction="horizontal" gap={6} align="center" justify="center">
                    <Text style={{
                      fontSize: 'var(--ggui-font-size-sm, 14px)',
                      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                      color: 'var(--ggui-color-primary-600, #0284c7)',
                    }}>
                      {day.high}°
                    </Text>
                    <Text style={{
                      fontSize: 'var(--ggui-font-size-sm, 14px)',
                      color: 'var(--ggui-color-neutral-500, #6b7280)',
                    }}>
                      {day.low}°
                    </Text>
                  </Stack>
                </div>
              ))}
            </Row>
          </Stack>
        )}
      </Stack>
    </Card>
  );
}

import { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Button,
  Divider,
} from '@ggui-ai/design/primitives';

// Email validation regex
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

interface SurveyAnswers {
  name: string;
  email: string;
  satisfactionRating: string;
  features: string[];
  comments: string;
}

interface Props {
  // Step 1 labels
  nameLabel?: string;
  emailLabel?: string;
  nameRequiredError?: string;
  emailRequiredError?: string;
  emailInvalidError?: string;

  // Step 2 - Satisfaction rating options
  satisfactionOptions?: Array<{ value: string; label: string; description?: string }>;
  satisfactionLabel?: string;

  // Step 3 - Feature interests
  featureOptions?: Array<{ value: string; label: string }>;
  featuresLabel?: string;

  // Step 4 - Comments
  commentsLabel?: string;
  commentsPlaceholder?: string;
  commentsMaxLength?: number;

  // Buttons and labels
  backButtonLabel?: string;
  nextButtonLabel?: string;
  submitButtonLabel?: string;

  // Callback
  onSubmit: (answers: SurveyAnswers) => void;
}

export default function MultiStepSurveyForm({
  // Step 1 defaults
  nameLabel = 'Full Name',
  emailLabel = 'Email Address',
  nameRequiredError = 'Name is required',
  emailRequiredError = 'Email is required',
  emailInvalidError = 'Please enter a valid email address',

  // Step 2 defaults
  satisfactionOptions = [
    { value: '1', label: 'Very Unsatisfied', description: 'Not happy at all' },
    { value: '2', label: 'Unsatisfied', description: 'Could be better' },
    { value: '3', label: 'Neutral', description: 'It was okay' },
    { value: '4', label: 'Satisfied', description: 'Pretty good' },
    { value: '5', label: 'Very Satisfied', description: 'Excellent!' },
  ],
  satisfactionLabel = 'How satisfied are you with our service?',

  // Step 3 defaults
  featureOptions = [
    { value: 'ease-of-use', label: 'Ease of Use' },
    { value: 'features', label: 'Feature Set' },
    { value: 'support', label: 'Customer Support' },
    { value: 'pricing', label: 'Pricing' },
    { value: 'reliability', label: 'Reliability' },
  ],
  featuresLabel = 'What features interested you most? (Select all that apply)',

  // Step 4 defaults
  commentsLabel = 'Additional Comments',
  commentsPlaceholder = 'Share any additional feedback or suggestions...',
  commentsMaxLength = 500,

  // Button labels
  backButtonLabel = 'Back',
  nextButtonLabel = 'Next',
  submitButtonLabel = 'Submit Survey',

  onSubmit,
}: Props) {
  const [currentStep, setCurrentStep] = useState(0);
  const [answers, setAnswers] = useState<SurveyAnswers>({
    name: '',
    email: '',
    satisfactionRating: '',
    features: [],
    comments: '',
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  const TOTAL_STEPS = 5; // Including review

  // Validation functions
  const validateName = (value: string) => {
    if (!value.trim()) return nameRequiredError;
    return '';
  };

  const validateEmail = (value: string) => {
    if (!value.trim()) return emailRequiredError;
    if (!EMAIL_REGEX.test(value)) return emailInvalidError;
    return '';
  };

  const isStep1Valid = () => {
    const nameError = validateName(answers.name);
    const emailError = validateEmail(answers.email);
    return !nameError && !emailError;
  };

  const isStep2Valid = () => {
    return answers.satisfactionRating !== '';
  };

  const isStep3Valid = () => {
    return answers.features.length > 0;
  };

  // Step-wise validation
  const isCurrentStepValid = () => {
    switch (currentStep) {
      case 0:
        return isStep1Valid();
      case 1:
        return isStep2Valid();
      case 2:
        return isStep3Valid();
      case 3:
        return true; // Comments are optional
      case 4:
        return true; // Review step
      default:
        return false;
    }
  };

  const updateField = (field: keyof SurveyAnswers, value: unknown) => {
    setAnswers((prev) => ({ ...prev, [field]: value }));
  };

  const handleNextStep = () => {
    const nameError = validateName(answers.name);
    const emailError = validateEmail(answers.email);

    if (currentStep === 0) {
      const newErrors: Record<string, string> = {};
      if (nameError) newErrors.name = nameError;
      if (emailError) newErrors.email = emailError;
      setErrors(newErrors);

      if (Object.keys(newErrors).length > 0) return;
    }

    if (currentStep < TOTAL_STEPS - 1) {
      setCurrentStep((prev) => prev + 1);
      setErrors({});
    }
  };

  const handlePreviousStep = () => {
    if (currentStep > 0) {
      setCurrentStep((prev) => prev - 1);
      setErrors({});
    }
  };

  const handleSubmit = () => {
    onSubmit(answers);
  };

  // Render step 1: Name and Email
  const renderStep1 = () => (
    <Stack direction="vertical" gap={16}>
      <Text variant="h3">Personal Information</Text>
      <Input
        label={nameLabel}
        placeholder="John Doe"
        value={answers.name}
        onChange={(v) => {
          updateField('name', v);
          const err = validateName(v);
          setErrors((prev) => ({ ...prev, name: err }));
        }}
        error={errors.name}
        required
      />
      <Input
        label={emailLabel}
        type="email"
        placeholder="john@example.com"
        value={answers.email}
        onChange={(v) => {
          updateField('email', v);
          const err = validateEmail(v);
          setErrors((prev) => ({ ...prev, email: err }));
        }}
        error={errors.email}
        required
      />
    </Stack>
  );

  // Render step 2: Satisfaction Rating
  const renderStep2 = () => (
    <Stack direction="vertical" gap={16}>
      <Text variant="h3">Satisfaction Rating</Text>
      <RadioGroup
        label={satisfactionLabel}
        value={answers.satisfactionRating}
        onChange={(v) => {
          updateField('satisfactionRating', v);
          setErrors((prev) => ({ ...prev, satisfactionRating: '' }));
        }}
        options={satisfactionOptions}
        direction="vertical"
        error={errors.satisfactionRating}
      />
    </Stack>
  );

  // Render step 3: Feature Interests
  const renderStep3 = () => (
    <Stack direction="vertical" gap={16}>
      <Text variant="h3">Feature Interests</Text>
      <Text variant="body">{featuresLabel}</Text>
      <Stack direction="vertical" gap={12}>
        {featureOptions.map((option) => (
          <Checkbox
            key={option.value}
            label={option.label}
            checked={answers.features.includes(option.value)}
            onChange={(checked) => {
              if (checked) {
                updateField('features', [
                  ...answers.features,
                  option.value,
                ]);
              } else {
                updateField(
                  'features',
                  answers.features.filter((f) => f !== option.value)
                );
              }
              setErrors((prev) => ({ ...prev, features: '' }));
            }}
          />
        ))}
      </Stack>
    </Stack>
  );

  // Render step 4: Comments
  const renderStep4 = () => {
    const charCount = answers.comments.length;
    const charDisplay = charCount + ' / ' + commentsMaxLength + ' characters';

    return (
      <Stack direction="vertical" gap={16}>
        <Text variant="h3">Additional Feedback</Text>
        <TextArea
          label={commentsLabel}
          placeholder={commentsPlaceholder}
          value={answers.comments}
          onChange={(v) => updateField('comments', v)}
          maxLength={commentsMaxLength}
          rows={5}
        />
        <Row justify="between" align="center">
          <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
            {charDisplay}
          </Text>
        </Row>
      </Stack>
    );
  };

  // Render step 5: Review
  const renderReview = () => {
    const selectedSatisfaction = satisfactionOptions.find(
      (opt) => opt.value === answers.satisfactionRating
    );
    const selectedFeatures = featureOptions.filter((opt) =>
      answers.features.includes(opt.value)
    );

    return (
      <Stack direction="vertical" gap={16}>
        <Text variant="h3">Review Your Answers</Text>

        <Card padding={16} shadow="sm">
          <Stack direction="vertical" gap={12}>
            <Text variant="label" weight="semibold">
              Personal Information
            </Text>
            <Row justify="between">
              <Text variant="body">Name:</Text>
              <Text variant="body" weight="medium">
                {answers.name}
              </Text>
            </Row>
            <Row justify="between">
              <Text variant="body">Email:</Text>
              <Text variant="body" weight="medium">
                {answers.email}
              </Text>
            </Row>
          </Stack>
        </Card>

        <Card padding={16} shadow="sm">
          <Stack direction="vertical" gap={12}>
            <Text variant="label" weight="semibold">
              Satisfaction Rating
            </Text>
            <Row justify="between">
              <Text variant="body">Rating:</Text>
              <Text variant="body" weight="medium">
                {selectedSatisfaction?.label} ({answers.satisfactionRating}/5)
              </Text>
            </Row>
          </Stack>
        </Card>

        <Card padding={16} shadow="sm">
          <Stack direction="vertical" gap={12}>
            <Text variant="label" weight="semibold">
              Feature Interests
            </Text>
            <Stack direction="vertical" gap={8}>
              {selectedFeatures.length > 0 ? (
                selectedFeatures.map((feature) => (
                  <Text key={feature.value} variant="body">
                    • {feature.label}
                  </Text>
                ))
              ) : (
                <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">
                  None selected
                </Text>
              )}
            </Stack>
          </Stack>
        </Card>

        {answers.comments.trim() && (
          <Card padding={16} shadow="sm">
            <Stack direction="vertical" gap={12}>
              <Text variant="label" weight="semibold">
                Additional Comments
              </Text>
              <Text variant="body">{answers.comments}</Text>
            </Stack>
          </Card>
        )}

        <Card
          padding={12}
          shadow="none"
          border={false}
          style={{
            backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
            borderLeft: '4px solid var(--ggui-color-primary-500, #0ea5e9)',
          }}
        >
          <Text variant="caption" color="var(--ggui-color-primary-900, #0c4a6e)">
            Please review your information above before submitting. If you need to make
            changes, use the Back button.
          </Text>
        </Card>
      </Stack>
    );
  };

  // Render current step content
  const renderStepContent = () => {
    switch (currentStep) {
      case 0:
        return renderStep1();
      case 1:
        return renderStep2();
      case 2:
        return renderStep3();
      case 3:
        return renderStep4();
      case 4:
        return renderReview();
      default:
        return null;
    }
  };

  // Progress bar calculation
  const progressPercentage = ((currentStep + 1) / TOTAL_STEPS) * 100;
  const progressStyle = {
    width: progressPercentage + '%',
    height: '100%',
    backgroundColor: 'var(--ggui-color-primary-500, #0ea5e9)',
    transition: 'width 300ms ease-out',
  };

  const stepDisplay = (currentStep + 1) + ' of ' + TOTAL_STEPS;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
      <Card padding="var(--ggui-spacing-6, 24px)" shadow="md">
        <Stack direction="vertical" gap="var(--ggui-spacing-6, 24px)">
          {/* Header */}
          <Stack direction="vertical" gap="var(--ggui-spacing-2, 8px)">
            <Text variant="h2">Customer Feedback Survey</Text>
            <Text
              variant="body"
              color="var(--ggui-color-neutral-500, #6b7280)"
            >
              Step {stepDisplay}
            </Text>
          </Stack>

          {/* Progress Bar */}
          <div
            style={{
              width: '100%',
              height: '8px',
              backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
              borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
              overflow: 'hidden',
            }}
          >
            <div style={progressStyle} />
          </div>

          {/* Content */}
          <div style={{ minHeight: '300px' }}>
            {renderStepContent()}
          </div>

          {/* Navigation Buttons */}
          <Row gap="var(--ggui-spacing-4, 16px)" justify="between">
            {currentStep > 0 ? (
              <Button variant="outline" onClick={handlePreviousStep}>
                {backButtonLabel}
              </Button>
            ) : (
              <div />
            )}

            {currentStep < TOTAL_STEPS - 1 ? (
              <Button
                variant="primary"
                onClick={handleNextStep}
                disabled={!isCurrentStepValid()}
              >
                {nextButtonLabel}
              </Button>
            ) : (
              <Button variant="primary" onClick={handleSubmit}>
                {submitButtonLabel}
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import { useState, useMemo } from 'react';
import {
  Container, Card, Stack, Row, Text, Input, Button, Select, Badge, Icon, Divider, Spacer
} from '@ggui-ai/design/primitives';

interface Task {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee?: { name: string; initials: string };
  dueDate?: string;
  columnId: 'todo' | 'inprogress' | 'done';
}

interface Props {
  tasks?: Task[];
  onTaskUpdate?: (tasks: Task[]) => void;
}

const COLUMNS = {
  todo: { id: 'todo', name: 'To Do' },
  inprogress: { id: 'inprogress', name: 'In Progress' },
  done: { id: 'done', name: 'Done' },
};

const PRIORITY_COLORS = {
  low: { variant: 'success' as const, label: 'Low' },
  medium: { variant: 'warning' as const, label: 'Medium' },
  high: { variant: 'error' as const, label: 'High' },
};

export default function GeneratedComponent({ tasks: initialTasks = [], onTaskUpdate }: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [expandedAddColumn, setExpandedAddColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Group tasks by column
  const tasksByColumn = useMemo(() => {
    const grouped = {
      todo: [] as Task[],
      inprogress: [] as Task[],
      done: [] as Task[],
    };
    tasks.forEach(task => {
      grouped[task.columnId].push(task);
    });
    return grouped;
  }, [tasks]);

  // Calculate stats
  const totalTasks = tasks.length;
  const completedTasks = tasksByColumn.done.length;

  // Handle task update
  const updateTasks = (newTasks: Task[]) => {
    setTasks(newTasks);
    onTaskUpdate?.(newTasks);
  };

  // Move task to another column
  const moveTask = (taskId: string, newColumnId: 'todo' | 'inprogress' | 'done') => {
    const updatedTasks = tasks.map(task =>
      task.id === taskId ? { ...task, columnId: newColumnId } : task
    );
    updateTasks(updatedTasks);
  };

  // Edit task title
  const startEditTask = (task: Task) => {
    setEditingTaskId(task.id);
    setEditingTitle(task.title);
  };

  const saveEditTask = (taskId: string) => {
    if (!editingTitle.trim()) return;
    const updatedTasks = tasks.map(task =>
      task.id === taskId ? { ...task, title: editingTitle } : task
    );
    updateTasks(updatedTasks);
    setEditingTaskId(null);
  };

  // Add new task
  const addTask = (columnId: 'todo' | 'inprogress' | 'done') => {
    if (!newTaskTitle.trim()) return;

    const timestamp = Date.now();
    const newTask: Task = {
      id: 'task-' + timestamp.toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      columnId,
    };

    updateTasks([...tasks, newTask]);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setExpandedAddColumn(null);
  };

  // Delete task
  const deleteTask = (taskId: string) => {
    updateTasks(tasks.filter(t => t.id !== taskId));
  };

  // Render task card
  const renderTaskCard = (task: Task) => (
    <Card key={task.id} padding={12} shadow="sm" border={true}>
      <Stack direction="vertical" gap={8}>
        {editingTaskId === task.id ? (
          <Stack direction="vertical" gap={8}>
            <Input
              label="Task title"
              value={editingTitle}
              onChange={setEditingTitle}
              placeholder="Task title"
              required
            />
            <Row gap={4}>
              <Button
                size="xs"
                variant="primary"
                onClick={() => saveEditTask(task.id)}
              >
                Save
              </Button>
              <Button
                size="xs"
                variant="secondary"
                onClick={() => setEditingTaskId(null)}
              >
                Cancel
              </Button>
            </Row>
          </Stack>
        ) : (
          <Row gap={8} align="center">
            <Text
              variant="body"
              weight="medium"
              style={{
                flex: 1,
                cursor: 'pointer',
                textDecoration: task.columnId === 'done' ? 'line-through' : 'none',
                color: task.columnId === 'done' ? 'var(--ggui-color-neutral-500, #6b7280)' : 'inherit',
              }}
              onDoubleClick={() => startEditTask(task)}
            >
              {task.title}
            </Text>
            <Button
              size="xs"
              variant="ghost"
              onClick={() => startEditTask(task)}
            >
              Edit
            </Button>
          </Row>
        )}

        <Stack direction="horizontal" gap={8} align="center" wrap={true}>
          <Badge variant={PRIORITY_COLORS[task.priority].variant} size="sm">
            {PRIORITY_COLORS[task.priority].label}
          </Badge>

          {task.assignee && (
            <div
              style={{
                width: 24,
                height: 24,
                borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                backgroundColor: 'var(--ggui-color-primary-200, #bae6fd)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: 'var(--ggui-font-size-xs, 12px)',
                fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                color: 'var(--ggui-color-primary-700, #0369a1)',
              }}
              title={task.assignee.name}
            >
              {task.assignee.initials}
            </div>
          )}

          {task.dueDate && (
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
              {new Date(task.dueDate).toLocaleDateString('en-US', {
                month: 'short',
                day: 'numeric',
              })}
            </Text>
          )}
        </Stack>

        <Stack direction="horizontal" gap={4}>
          <Select
            label="Move task to column"
            value={task.columnId}
            onChange={(newColumnId) => moveTask(task.id, newColumnId as 'todo' | 'inprogress' | 'done')}
            options={[
              { value: 'todo', label: 'To Do' },
              { value: 'inprogress', label: 'In Progress' },
              { value: 'done', label: 'Done' },
            ]}
          />
          <Button
            size="xs"
            variant="danger"
            onClick={() => deleteTask(task.id)}
          >
            Delete
          </Button>
        </Stack>
      </Stack>
    </Card>
  );

  // Render column
  const renderColumn = (columnKey: 'todo' | 'inprogress' | 'done') => {
    const column = COLUMNS[columnKey];
    const columnTasks = tasksByColumn[columnKey];

    return (
      <Card key={column.id} padding={16} shadow="sm" border={true}>
        <Stack direction="vertical" gap={12} align="stretch">
          {/* Column Header */}
          <Row justify="between" align="center">
            <Text variant="h3" weight="semibold">
              {column.name}
            </Text>
            <Badge variant="secondary" size="sm">
              {columnTasks.length}
            </Badge>
          </Row>

          <Divider />

          {/* Task List */}
          <Stack direction="vertical" gap={8} align="stretch">
            {columnTasks.map(task => renderTaskCard(task))}
          </Stack>

          <Divider />

          {/* Add Task Button */}
          {expandedAddColumn === column.id ? (
            <Stack direction="vertical" gap={8}>
              <Input
                label="New task title"
                placeholder="Enter task title"
                value={newTaskTitle}
                onChange={setNewTaskTitle}
                required
              />
              <Select
                label="Task priority"
                value={newTaskPriority}
                onChange={(value) => setNewTaskPriority(value as 'low' | 'medium' | 'high')}
                options={[
                  { value: 'low', label: 'Low' },
                  { value: 'medium', label: 'Medium' },
                  { value: 'high', label: 'High' },
                ]}
              />
              <Row gap={4}>
                <Button
                  variant="primary"
                  size="sm"
                  fullWidth={true}
                  onClick={() => addTask(column.id as 'todo' | 'inprogress' | 'done')}
                >
                  Add
                </Button>
                <Button
                  variant="secondary"
                  size="sm"
                  onClick={() => {
                    setExpandedAddColumn(null);
                    setNewTaskTitle('');
                    setNewTaskPriority('medium');
                  }}
                >
                  Cancel
                </Button>
              </Row>
            </Stack>
          ) : (
            <Button
              variant="outline"
              size="sm"
              fullWidth={true}
              leftIcon={<Icon name="plus" size={16} />}
              onClick={() => setExpandedAddColumn(column.id)}
            >
              Add Task
            </Button>
          )}
        </Stack>
      </Card>
    );
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack direction="vertical" gap={24} align="stretch">
        {/* Summary Bar */}
        <Card padding={16} shadow="sm" border={true}>
          <Stack direction="horizontal" gap={32} align="center">
            <Stack direction="vertical" gap={4}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                Total Tasks
              </Text>
              <Text variant="h2">{totalTasks}</Text>
            </Stack>
            <Stack direction="vertical" gap={4}>
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                Completed
              </Text>
              <Text variant="h2">
                {completedTasks} / {totalTasks}
              </Text>
            </Stack>
            <Spacer />
            <div
              style={{
                width: '100%',
                height: 8,
                backgroundColor: 'var(--ggui-color-neutral-200, #e5e7eb)',
                borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                overflow: 'hidden',
                maxWidth: 200,
              }}
            >
              <div
                style={{
                  height: '100%',
                  backgroundColor: totalTasks > 0
                    ? 'var(--ggui-color-success-500, #22c55e)'
                    : 'var(--ggui-color-neutral-300, #d1d5db)',
                  width: totalTasks > 0 ? (completedTasks / totalTasks) * 100 + '%' : '0%',
                  transition: 'width 200ms ease-out',
                }}
              />
            </div>
          </Stack>
        </Card>

        {/* Kanban Board */}
        <Row gap={16} align="start" wrap={true}>
          {renderColumn('todo')}
          {renderColumn('inprogress')}
          {renderColumn('done')}
        </Row>
      </Stack>
    </Container>
  );
}

