interface ElementCellProps {
  element: Element;
  isVisible: boolean;
  isSelected: boolean;
  onClick: (element: Element) => void;
}

function ElementCell({ element, isVisible, isSelected, onClick }: ElementCellProps) {
  const { motionEnabled } = useMotion();
  const colors = CATEGORY_COLORS[element.category] || {
    bg: 'var(--ggui-color-neutral-300)',
    text: 'var(--ggui-color-neutral-900)',
    border: 'var(--ggui-color-neutral-400)',
  };

  const ariaLabel = element.symbol + ' - ' + element.name + ' (Atomic number ' + element.atomicNumber + ')';

  return (
    <div
      onClick={() => onClick(element)}
      style={{
        width: '100%',
        aspectRatio: '1',
        padding: 'var(--ggui-spacing-2)',
        backgroundColor: colors.bg,
        border: colors.border,
        borderStyle: 'solid',
        borderWidth: '2px',
        borderRadius: 'var(--ggui-shape-radius-md)',
        cursor: 'pointer',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'space-between',
        alignItems: 'center',
        textAlign: 'center',
        opacity: isVisible ? 1 : 0.2,
        transform: isSelected ? 'scale(1.05)' : 'scale(1)',
        transition: motionEnabled ? 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)' : 'none',
        boxShadow: isSelected ? 'var(--ggui-shape-shadow-lg)' : 'var(--ggui-shape-shadow-sm)',
      } as React.CSSProperties}
      role="button"
      tabIndex={0}
      aria-label={ariaLabel}
      onKeyDown={(e) => {
        if (e.key === 'Enter' || e.key === ' ') {
          onClick(element);
        }
      }}
    >
      <Text
        variant="caption"
        color={colors.text}
        weight="medium"
        style={{ fontSize: 'var(--ggui-font-size-xs)' }}
      >
        {element.atomicNumber}
      </Text>
      <Text
        variant="h3"
        color={colors.text}
        weight="bold"
        style={{ fontSize: 'var(--ggui-font-size-lg)' }}
      >
        {element.symbol}
      </Text>
    </div>
  );
}

