export default function PeriodicTable({ elements, onElementClick }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);
  const { motionEnabled } = useMotion();

  // Filter elements based on search
  const filteredElements = useMemo(() => {
    if (!searchQuery) return elements;
    const query = searchQuery.toLowerCase();
    return elements.filter(
      (el) =>
        el.symbol.toLowerCase().includes(query) ||
        el.name.toLowerCase().includes(query)
    );
  }, [elements, searchQuery]);

  // Create visibility map
  const visibleSet = new Set(filteredElements.map((el) => el.atomicNumber));

  // Grid positioning for periodic table (18 columns, with gaps for lanthanides/actinides)
  const getGridPosition = (element: Element) => {
    const { period, group } = element;
    let column = group;
    let row = period;

    // Adjust for lanthanides and actinides to be placed below main table
    if (element.category === 'Lanthanide') {
      row = 9;
      column = element.atomicNumber - 56;
    } else if (element.category === 'Actinide') {
      row = 10;
      column = element.atomicNumber - 88;
    }

    return { column, row };
  };

  // Build grid layout
  const gridItems = elements.map((element) => {
    const pos = getGridPosition(element);
    return { element, ...pos };
  });

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="full" padding={24}>
        <Stack direction="vertical" gap={24}>
          {/* Header */}
          <div>
            <Text
              variant="h1"
              weight="bold"
              style={{ marginBottom: 'var(--ggui-spacing-4)' }}
            >
              Interactive Periodic Table of Elements
            </Text>
            <Text color="var(--ggui-color-neutral-500)" variant="body">
              Click on any element to view detailed information. Use the search to filter by name or symbol.
            </Text>
          </div>

          {/* Search Input */}
          <Input
            label="Search elements"
            placeholder="Search by element name or symbol (e.g., 'Gold' or 'Au')..."
            value={searchQuery}
            onChange={setSearchQuery}
            leftIcon={<Icon name="search" size={18} />}
          />

          {/* Legend */}
          <Legend />

          {/* Results counter */}
          {searchQuery && (
            <Text
              variant="caption"
              color="var(--ggui-color-neutral-500)"
              style={{
                animation: motionEnabled ? 'ggui-fadeIn 200ms ease-out' : 'none',
              }}
            >
              Showing {filteredElements.length} of {elements.length} elements
            </Text>
          )}

          {/* Periodic Table Grid */}
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(60px, 1fr))',
              gap: 'var(--ggui-spacing-2)',
              gridAutoRows: 'auto',
              padding: 'var(--ggui-spacing-4)',
              backgroundColor: 'var(--ggui-color-neutral-50)',
              borderRadius: 'var(--ggui-shape-radius-lg)',
              borderWidth: '1px',
              borderStyle: 'solid',
              borderColor: 'var(--ggui-color-neutral-200)',
            }}
            role="grid"
            aria-label="Periodic table of elements"
          >
            {gridItems.map(({ element, column, row }) => (
              <div
                key={element.atomicNumber}
                style={{
                  gridColumn: column,
                  gridRow: row,
                }}
                role="gridcell"
              >
                <ElementCell
                  element={element}
                  isVisible={visibleSet.has(element.atomicNumber)}
                  isSelected={selectedElement?.atomicNumber === element.atomicNumber}
                  onClick={(el) => {
                    setSelectedElement(el);
                    onElementClick?.(el);
                  }}
                />
              </div>
            ))}
          </div>
        </Stack>
      </Container>

      {/* Detail Panel */}
      <DetailPanel
        element={selectedElement}
        onClose={() => setSelectedElement(null)}
      />
    </>
  );
}

