// Helper function to format price
function formatPrice(price: number, symbol: string): string {
  return symbol + price.toFixed(2);
}

// Helper function to render star rating
function StarRating({
  rating,
  size = 16,
}: {
  rating: number;
  size?: number;
}): React.ReactNode {
  const stars = [];
  const fullStars = Math.floor(rating);
  const hasHalf = rating % 1 !== 0;

  for (let i = 1; i <= 5; i++) {
    if (i <= fullStars) {
      stars.push(
        <span key={i} style={{ color: 'var(--ggui-color-warning-500)' }}>
          ★
        </span>
      );
    } else if (i === fullStars + 1 && hasHalf) {
      stars.push(
        <span
          key={i}
          style={{
            color: 'var(--ggui-color-warning-500)',
            opacity: 0.5,
          }}
        >
          ★
        </span>
      );
    } else {
      stars.push(
        <span
          key={i}
          style={{
            color: 'var(--ggui-color-neutral-300)',
          }}
        >
          ★
        </span>
      );
    }
  }

  return (
    <span style={{ fontSize: size + 'px', letterSpacing: '2px' }}>
      {stars}
    </span>
  );
}

