              </Text>
            </Stack>
          </div>

          {/* Product Details */}
          <Stack direction="vertical" gap={16} style={{ flex: '1 1 50%', minWidth: 0 }}>
            {/* Title */}
            <Text variant="h2">{props.productName}</Text>

            {/* Price */}
            <Text
              variant="h3"
              color="var(--ggui-color-primary-600)"
              style={{ fontSize: 'var(--ggui-font-size-2xl)' }}
            >
              {formatPrice(props.price, props.currencySymbol)}
            </Text>

            {/* Rating */}
            <Row gap={8} align="center">
              <div style={{ marginTop: '2px' }}>
                <StarRating rating={props.rating} size={18} />
              </div>
              <Text
                variant="body"
                color="var(--ggui-color-neutral-600)"
                weight="medium"
              >
                {props.rating.toFixed(1)} ({props.ratingCount} reviews)
              </Text>
            </Row>

            {/* Stock Status Badge */}
            <Badge variant={stockBadgeVariant} size="md">
              {stockStatus}
            </Badge>

            {/* Divider */}
            <Divider margin={8} />

            {/* Quantity & Add to Cart */}
            <Stack direction="vertical" gap={12}>
              <Text weight="semibold">Quantity</Text>
              <Row gap={8} align="center">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleQuantityChange(quantity - 1)}
                  disabled={quantity <= 1}
                >
                  <Icon name="minus" size={16} />
                </Button>

                <Input
                  type="number"
                  value={String(quantity)}
                  onChange={(v) => handleQuantityChange(parseInt(v) || 1)}
                  label="Quantity"
                />

                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => handleQuantityChange(quantity + 1)}
                  disabled={quantity >= props.stock}
                >
                  <Icon name="plus" size={16} />
                </Button>

                <Text
                  variant="caption"
                  color="var(--ggui-color-neutral-500)"
                  style={{ marginLeft: '8px' }}
                >
                  {props.stock} available
                </Text>
              </Row>
            </Stack>

            {/* Add to Cart Button */}
            <Button
              variant="primary"
              size="lg"
              onClick={handleAddToCart}
              disabled={!isInStock}
              fullWidth
            >
              {isInStock ? 'Add to Cart' : 'Out of Stock'}
            </Button>
          </Stack>
        </Row>

        {/* Divider */}
        <Divider margin={16} />

        {/* Middle Section: Tabs */}
        <Card padding={0} border={false} shadow="sm">
          <Tabs
            activeKey={activeTab}
            onChange={setActiveTab}
            items={tabItems}
            variant="line"
            size="md"
            fullWidth
          />
        </Card>
      </Stack>
    </Container>
  );
}

