import { useState, useEffect, useRef } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Button,
  Icon,
  Box,
} from '@ggui-ai/design/primitives';

interface Message {
  id: string;
  sender: string;
  senderName: string;
  text: string;
  timestamp: string;
}

interface TypingUser {
  sender: string;
  senderName: string;
}

interface User {
  id: string;
  name: string;
}

interface Props {
  title: string;
  participantCount: number;
  currentUser: User;
  initialMessages?: Message[];
  onSend: (data: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title,
  participantCount,
  currentUser,
  initialMessages = [],
  onSend,
}: Props) {
  const [messages, setMessages] = useState<Message[]>(initialMessages);
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<TypingUser[]>([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, typingUsers]);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      try {
        const customEvent = event as CustomEvent;
        const eventDetail = customEvent.detail;
        const eventType = eventDetail.type;

        if (eventType === 'message') {
          const sender = eventDetail.sender;
          const senderName = eventDetail.senderName;
          const text = eventDetail.text;
          const timestamp = eventDetail.timestamp;
          const newId = String(Date.now());

          const newMessage: Message = {
            id: newId,
            sender,
            senderName,
            text,
            timestamp,
          };
          setMessages((prev) => [...prev, newMessage]);
        } else if (eventType === 'typing') {
          const sender = eventDetail.sender;
          const senderName = eventDetail.senderName;

          setTypingUsers((prev) => {
            const exists = prev.some((u) => u.sender === sender);
            if (!exists) {
              return [...prev, { sender, senderName }];
            }
            return prev;
          });

          const timerId = setTimeout(() => {
            setTypingUsers((prev) =>
              prev.filter((u) => u.sender !== sender)
            );
          }, 3000);

          return () => clearTimeout(timerId);
        }
      } catch (err) {
        void err;
      }
    };

    if (typeof window !== 'undefined' && window !== null) {
      const w = window as any;
      w.addEventListener('ggui:agent-data', handleAgentData);
      return () => {
        w.removeEventListener('ggui:agent-data', handleAgentData);
      };
    }
  }, []);

  const handleSend = () => {
    const trimmedValue = inputValue.trim();
    if (trimmedValue) {
      const timestamp = new Date().toISOString();
      onSend({ text: trimmedValue, timestamp });
      setInputValue('');
    }
  };

  return (
    <Container maxWidth="lg" padding={0}>
      <Card shadow="none" border={false} padding={0}>
        <Stack direction="vertical" gap={0} align="stretch">
          {/* Header */}
          <Box
            padding="var(--ggui-spacing-4, 16px)"
            background="var(--ggui-color-primary-50, #f0f9ff)"
            borderRadius="0"
            style={{
              borderBottom: '1px solid var(--ggui-color-primary-200, #bae6fd)',
            }}
          >
            <Row justify="between" align="center">
              <Stack direction="vertical" gap={2}>
                <Text
                  variant="h3"
                  color="var(--ggui-color-primary-900, #0c4a6e)"
                  weight="semibold"
                >
                  {title}
                </Text>
                <Text
                  variant="caption"
                  color="var(--ggui-color-primary-700, #0369a1)"
                >
                  {participantCount}
                  {participantCount !== 1 ? ' participants' : ' participant'}
                </Text>
              </Stack>
            </Row>
          </Box>

          {/* Messages Area */}
          <Box
            padding="var(--ggui-spacing-4, 16px)"
            style={{
              flex: 1,
              overflowY: 'auto',
              minHeight: '400px',
              maxHeight: '600px',
              backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
            }}
            ref={containerRef}
          >
            <Stack direction="vertical" gap={12} align="stretch">
              {messages.map((msg) => {
                const isCurrentUser = msg.sender === currentUser.id;
                return (
                  <Row
                    key={msg.id}
                    justify={isCurrentUser ? 'end' : 'start'}
                    align="start"
                    gap={8}
                  >
                    <Box
                      padding="var(--ggui-spacing-3, 12px) var(--ggui-spacing-4, 16px)"
                      borderRadius="var(--ggui-shape-radius-lg, 12px)"
                      style={{
                        maxWidth: '70%',
                        wordWrap: 'break-word',
                        backgroundColor: isCurrentUser
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-neutral-200, #e5e7eb)',
                        boxShadow: 'var(--ggui-shape-shadow-sm)',
                      }}
                    >
                      <Stack direction="vertical" gap={4}>
                        <Text
                          variant="label"
                          weight="semibold"
                          color={
                            isCurrentUser
                              ? 'var(--ggui-color-neutral-50, #f9fafb)'
                              : 'var(--ggui-color-neutral-900, #111827)'
                          }
                        >
                          {msg.senderName}
                        </Text>
                        <Text
                          variant="body"
                          color={
                            isCurrentUser
                              ? 'var(--ggui-color-neutral-50, #f9fafb)'
                              : 'var(--ggui-color-neutral-900, #111827)'
                          }
                        >
                          {msg.text}
                        </Text>
                        <Text
                          variant="caption"
                          color={
                            isCurrentUser
                              ? 'var(--ggui-color-primary-200, #bae6fd)'
                              : 'var(--ggui-color-neutral-500, #6b7280)'
                          }
                        >
                          {new Date(msg.timestamp).toLocaleTimeString(
                            undefined,
                            {
                              hour: '2-digit',
                              minute: '2-digit',
                            }
                          )}
                        </Text>
                      </Stack>
                    </Box>
                  </Row>
                );
              })}

              {/* Typing Indicator */}
              {typingUsers.length > 0 && (
                <Row justify="start" align="center" gap={8}>
                  <Box
                    padding="var(--ggui-spacing-3, 12px) var(--ggui-spacing-4, 16px)"
                    borderRadius="var(--ggui-shape-radius-lg, 12px)"
                    style={{
                      backgroundColor:
                        'var(--ggui-color-neutral-200, #e5e7eb)',
                      boxShadow: 'var(--ggui-shape-shadow-sm)',
                    }}
                  >
                    <Stack direction="vertical" gap={4}>
                      <Text
                        variant="label"
                        weight="semibold"
                        color="var(--ggui-color-neutral-900, #111827)"
                      >
                        {typingUsers.length === 1
                          ? typingUsers[0].senderName
                          : typingUsers.map((u) => u.senderName).join(', ')}
                      </Text>
                      <div
                        style={{
                          display: 'flex',
                          gap: 'var(--ggui-spacing-1, 4px)',
                          alignItems: 'center',
                        }}
                      >
                        {[0, 1, 2].map((i) => (
                          <div
                            key={i}
                            style={{
                              width: 'var(--ggui-spacing-2, 8px)',
                              height: 'var(--ggui-spacing-2, 8px)',
                              borderRadius: '50%',
                              backgroundColor:
                                'var(--ggui-color-neutral-500, #6b7280)',
                              animation: 'pulse 1.4s infinite',
                              animationDelay: (i * 0.2) + 's',
                            }}
                          />
                        ))}
                      </div>
                    </Stack>
                  </Box>
                </Row>
              )}

              <div ref={messagesEndRef} />
            </Stack>
          </Box>

          {/* Input Area */}
          <Box
            padding="var(--ggui-spacing-4, 16px)"
            style={{
              borderTop: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
              backgroundColor: 'var(--ggui-color-neutral-50, #f9fafb)',
            }}
          >
            <Stack direction="vertical" gap={12} align="stretch">
              <Input
                label="Message"
                placeholder="Type a message..."
                value={inputValue}
                onChange={setInputValue}
              />
              <Row gap={8} align="center" justify="end">
                <Button
                  variant="primary"
                  size="md"
                  disabled={!inputValue.trim()}
                  onClick={handleSend}
                  rightIcon={<Icon name="chevron-right" size={16} />}
                >
                  Send
                </Button>
              </Row>
            </Stack>
          </Box>
        </Stack>
      </Card>

      <style>{`
        @keyframes pulse {
          0%, 100% {
            opacity: 1;
          }
          50% {
            opacity: 0.4;
          }
        }
      `}</style>
    </Container>
  );
}

import { MotionKeyframes, useMotion, Card } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

// ─── Types ───────────────────────────────────────────────────────────────────

export type WeatherCondition =
  | 'sunny'
  | 'partly-cloudy'
  | 'cloudy'
  | 'rainy'
  | 'stormy'
  | 'snowy'
  | 'windy'
  | 'foggy';

export interface ForecastDay {
  day: string;
  condition: WeatherCondition;
  high: number;
  low: number;
}

interface Props {
  city?: string;
  country?: string;
  temperature?: number;
  feelsLike?: number;
  condition?: WeatherCondition;
  humidity?: number;
  windSpeed?: number;
  windUnit?: string;
  tempUnit?: string;
  forecast?: ForecastDay[];
}

// ─── Condition metadata ───────────────────────────────────────────────────────

const CONDITION_META: Record<
  WeatherCondition,
  { emoji: string; label: string; bg: string }
> = {
  'sunny':         { emoji: '☀️',  label: 'Sunny',         bg: 'linear-gradient(135deg, var(--ggui-color-warning-500, #f59e0b), var(--ggui-color-warning-600, #d97706))' },
  'partly-cloudy': { emoji: '⛅',  label: 'Partly Cloudy', bg: 'linear-gradient(135deg, var(--ggui-color-primary-400, #38bdf8), var(--ggui-color-primary-600, #0284c7))' },
  'cloudy':        { emoji: '☁️',  label: 'Cloudy',         bg: 'linear-gradient(135deg, var(--ggui-color-neutral-500, #6b7280), var(--ggui-color-neutral-700, #374151))' },
  'rainy':         { emoji: '🌧️',  label: 'Rainy',          bg: 'linear-gradient(135deg, var(--ggui-color-primary-600, #0284c7), var(--ggui-color-primary-800, #075985))' },
  'stormy':        { emoji: '⛈️',  label: 'Stormy',         bg: 'linear-gradient(135deg, var(--ggui-color-neutral-700, #374151), var(--ggui-color-neutral-900, #111827))' },
  'snowy':         { emoji: '❄️',  label: 'Snowy',          bg: 'linear-gradient(135deg, var(--ggui-color-primary-200, #bae6fd), var(--ggui-color-primary-400, #38bdf8))' },
  'windy':         { emoji: '💨',  label: 'Windy',          bg: 'linear-gradient(135deg, var(--ggui-color-primary-300, #7dd3fc), var(--ggui-color-primary-500, #0ea5e9))' },
  'foggy':         { emoji: '🌫️',  label: 'Foggy',          bg: 'linear-gradient(135deg, var(--ggui-color-neutral-300, #d1d5db), var(--ggui-color-neutral-500, #6b7280))' },
};

// Pre-computed staggered fade delays for the 5 forecast columns
const FORECAST_DELAYS = ['0ms', '60ms', '120ms', '180ms', '240ms'];

// ─── Defaults ─────────────────────────────────────────────────────────────────

const DEFAULT_FORECAST: ForecastDay[] = [
  { day: 'Mon', condition: 'sunny',         high: 28, low: 18 },
  { day: 'Tue', condition: 'partly-cloudy', high: 24, low: 16 },
  { day: 'Wed', condition: 'rainy',         high: 19, low: 13 },
  { day: 'Thu', condition: 'cloudy',        high: 21, low: 14 },
  { day: 'Fri', condition: 'sunny',         high: 26, low: 17 },
];

// ─── Sub-components ───────────────────────────────────────────────────────────

interface StatPillProps {
  icon: string;
  label: string;
  value: string;
}

function StatPill({ icon, label, value }: StatPillProps) {
  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      gap: 'var(--ggui-spacing-1, 4px)',
      padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
      background: 'rgba(255,255,255,0.15)',
      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
      backdropFilter: 'blur(4px)',
      flex: 1,
      minWidth: 0,
    }}>
      <span style={{ fontSize: '1.25rem', lineHeight: 1 }}>{icon}</span>
      <span style={{
        fontSize: 'var(--ggui-font-size-xs, 12px)',
        color: 'rgba(255,255,255,0.75)',
        fontWeight: 'var(--ggui-font-weight-medium, 500)',
        textTransform: 'uppercase' as const,
        letterSpacing: '0.05em',
        whiteSpace: 'nowrap' as const,
      }}>
        {label}
      </span>
      <span style={{
        fontSize: 'var(--ggui-font-size-base, 16px)',
        fontWeight: 'var(--ggui-font-weight-semibold, 600)',
        color: 'var(--ggui-color-neutral-50, #f9fafb)',
        whiteSpace: 'nowrap' as const,
      }}>
        {value}
      </span>
    </div>
  );
}

interface ForecastItemProps {
  day: ForecastDay;
  tempUnit: string;
  motionEnabled: boolean;
  delay: string;
}

function ForecastItem({ day, tempUnit, motionEnabled, delay }: ForecastItemProps) {
  const meta = CONDITION_META[day.condition] ?? CONDITION_META['sunny'];
  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      gap: 'var(--ggui-spacing-1, 4px)',
      flex: 1,
      minWidth: 0,
      padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-1, 4px)',
      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
      animationName: motionEnabled ? 'ggui-fadeIn' : 'none',
      animationDuration: '300ms',
      animationTimingFunction: 'ease-out',
      animationDelay: delay,
      animationFillMode: 'both' as const,
    }}>
      <span style={{
        fontSize: 'var(--ggui-font-size-xs, 12px)',
        fontWeight: 'var(--ggui-font-weight-semibold, 600)',
        color: 'var(--ggui-color-neutral-500, #6b7280)',
        textTransform: 'uppercase' as const,
        letterSpacing: '0.05em',
      }}>
        {day.day}
      </span>
      <span style={{ fontSize: '1.4rem', lineHeight: 1.2 }}>{meta.emoji}</span>
      <span style={{
        fontSize: 'var(--ggui-font-size-sm, 14px)',
        fontWeight: 'var(--ggui-font-weight-semibold, 600)',
        color: 'var(--ggui-color-neutral-900, #111827)',
      }}>
        {day.high}{tempUnit}
      </span>
      <span style={{
        fontSize: 'var(--ggui-font-size-xs, 12px)',
        color: 'var(--ggui-color-neutral-500, #6b7280)',
      }}>
        {day.low}{tempUnit}
      </span>
    </div>
  );
}

// ─── Main Component ────────────────────────────────────────────────────────────

export default function GeneratedComponent({
  city = 'San Francisco',
  country = 'US',
  temperature = 23,
  feelsLike = 21,
  condition = 'partly-cloudy',
  humidity = 62,
  windSpeed = 18,
  windUnit = 'km/h',
  tempUnit = '°C',
  forecast = DEFAULT_FORECAST,
}: Props) {
  const { motionEnabled } = useMotion();
