          {/* Location row + condition badge */}
          <div style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
          }}>
            <div>
              <div style={{
                fontSize: 'var(--ggui-font-size-xl, 20px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-neutral-50, #f9fafb)',
                lineHeight: 1.2,
              }}>
                {city}
              </div>
              <div style={{
                fontSize: 'var(--ggui-font-size-sm, 14px)',
                color: 'rgba(255,255,255,0.75)',
                marginTop: 'var(--ggui-spacing-1, 4px)',
              }}>
                {country}
              </div>
            </div>

            {/* Condition pill */}
            <div style={{
              display: 'flex',
              alignItems: 'center',
              gap: 'var(--ggui-spacing-1, 4px)',
              paddingTop: 'var(--ggui-spacing-1, 4px)',
              paddingBottom: 'var(--ggui-spacing-1, 4px)',
              paddingLeft: 'var(--ggui-spacing-2, 8px)',
              paddingRight: 'var(--ggui-spacing-2, 8px)',
              background: 'rgba(255,255,255,0.2)',
              borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
              backdropFilter: 'blur(4px)',
            }}>
              <span style={{ fontSize: '0.9rem' }}>{meta.emoji}</span>
              <span style={{
                fontSize: 'var(--ggui-font-size-xs, 12px)',
                fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                color: 'var(--ggui-color-neutral-50, #f9fafb)',
                whiteSpace: 'nowrap' as const,
              }}>
                {meta.label}
              </span>
            </div>
          </div>

          {/* Giant temperature */}
          <div style={{
            display: 'flex',
            alignItems: 'flex-start',
            justifyContent: 'center',
            gap: 'var(--ggui-spacing-2, 8px)',
