              {temperature}
            </span>
            <span style={{
              fontSize: 'var(--ggui-font-size-4xl, 36px)',
              fontWeight: 'var(--ggui-font-weight-medium, 500)',
              color: 'rgba(255,255,255,0.85)',
              lineHeight: 1,
              paddingTop: 'var(--ggui-spacing-2, 8px)',
