              {tempUnit}
            </span>
          </div>

          {/* Feels like */}
          <div style={{
            textAlign: 'center' as const,
            fontSize: 'var(--ggui-font-size-sm, 14px)',
            color: 'rgba(255,255,255,0.75)',
            marginTop: 'calc(var(--ggui-spacing-2, 8px) * -1)',
          }}>
            Feels like {feelsLike}{tempUnit}
          </div>

          {/* Stat pills — humidity + wind */}
          <div style={{ display: 'flex', gap: 'var(--ggui-spacing-2, 8px)' }}>
            <StatPill icon="💧" label="Humidity" value={humidity + '%'} />
            <StatPill icon="🌬️" label="Wind"     value={windSpeed + ' ' + windUnit} />
          </div>

        </div>

        {/* ── 5-day forecast strip ── */}
        <div style={{
          padding: 'var(--ggui-spacing-4, 16px) var(--ggui-spacing-4, 16px) var(--ggui-spacing-6, 24px)',
          background: 'var(--ggui-color-neutral-50, #f9fafb)',
          borderRadius: '0 0 var(--ggui-shape-radius-xl, 16px) var(--ggui-shape-radius-xl, 16px)',
