            {safeForecast.map((day, i) => (
              <ForecastItem
                key={day.day + '-' + i}
                day={day}
                tempUnit={tempUnit}
                motionEnabled={motionEnabled}
                delay={FORECAST_DELAYS[i] ?? '0ms'}
              />
            ))}
          </div>
        </div>

      </Card>
    </>
  );
}

import { useState, useCallback } from 'react';
import {
  Container, Card, Stack, Row,
  Text, Divider,
  Button, Input, TextArea, RadioGroup, Checkbox, Icon,
  Badge, MotionKeyframes, useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

// ─── Types ────────────────────────────────────────────────────────────────────

interface RatingOption {
  value: string;
  label: string;
  description?: string;
}

interface FeatureOption {
  value: string;
  label: string;
  description?: string;
}

interface SurveyAnswers {
  name: string;
  email: string;
  rating: string;
  features: string[];
  comments: string;
}

interface Props {
  surveyTitle?: string;
  surveyDescription?: string;
  ratingOptions?: RatingOption[];
  featureOptions?: FeatureOption[];
  maxCommentLength?: number;
  onSubmit?: (answers: SurveyAnswers) => void;
}

// ─── Defaults ────────────────────────────────────────────────────────────────

const DEFAULT_RATING_OPTIONS: RatingOption[] = [
  { value: '1', label: '1 – Very Dissatisfied', description: 'I had a poor experience' },
  { value: '2', label: '2 – Dissatisfied',       description: 'Several issues encountered' },
  { value: '3', label: '3 – Neutral',             description: 'Neither good nor bad' },
  { value: '4', label: '4 – Satisfied',           description: 'Mostly positive experience' },
  { value: '5', label: '5 – Very Satisfied',      description: 'Excellent experience!' },
];

const DEFAULT_FEATURE_OPTIONS: FeatureOption[] = [
  { value: 'dashboard',     label: 'Dashboard & Analytics',    description: 'Real-time charts and reporting' },
  { value: 'integrations',  label: 'Third-party Integrations', description: 'Connect your existing tools' },
  { value: 'automation',    label: 'Workflow Automation',      description: 'Automate repetitive tasks' },
  { value: 'collaboration', label: 'Team Collaboration',       description: 'Real-time multiplayer editing' },
  { value: 'mobile',        label: 'Mobile App',               description: 'iOS and Android support' },
  { value: 'api',           label: 'Developer API',            description: 'Programmatic access & webhooks' },
];

const STEP_LABELS = ['Your Info', 'Satisfaction', 'Interests', 'Comments'];
const TOTAL_STEPS = 4;

// ─── Helpers ──────────────────────────────────────────────────────────────────

const isValidEmail = (v: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v.trim());

// ─── ProgressHeader ───────────────────────────────────────────────────────────

function ProgressHeader({ currentStep, totalSteps, stepLabels }: { currentStep: number; totalSteps: number; stepLabels: string[] }) {
  const pct = Math.round((currentStep / totalSteps) * 100);
  const progressLabel = 'Survey progress indicator';
  const barWidth = pct + '%';

  return (
    <Stack gap={12} direction="vertical">
      <Row align="center" justify="between">
        <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">
          Step {currentStep} of {totalSteps}
        </Text>
        <Badge variant="primary" size="sm" pill>
          {stepLabels[Math.min(currentStep - 1, stepLabels.length - 1)]}
        </Badge>
      </Row>

      <div
        role="progressbar"
        aria-valuenow={pct}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label={progressLabel}
        style={{
          width: '100%',
          height: 8,
          borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
          background: 'var(--ggui-color-neutral-200, #e5e7eb)',
          overflow: 'hidden',
        }}
      >
        <div style={{
          height: '100%',
          width: barWidth,
          borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
          background: 'linear-gradient(90deg, var(--ggui-color-primary-500, #0ea5e9), var(--ggui-color-primary-600, #0284c7))',
          transition: 'width 400ms cubic-bezier(0.4, 0, 0.2, 1)',
        }} />
      </div>

      <Row gap={8} justify="between">
        {stepLabels.map((label, i) => {
          const stepNum   = i + 1;
          const isDone    = currentStep > stepNum;
          const isCurrent = currentStep === stepNum;
          return (
            <Stack key={label} align="center" gap={4} direction="vertical">
              <div style={{
                width: 28, height: 28,
                borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 'var(--ggui-font-size-xs, 12px)',
                fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                transition: 'background 300ms ease, color 300ms ease',
                background: isDone ? 'var(--ggui-color-primary-600, #0284c7)' : isCurrent ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-neutral-100, #f3f4f6)',
                color: isDone ? 'var(--ggui-color-neutral-50, #f9fafb)' : isCurrent ? 'var(--ggui-color-primary-700, #0369a1)' : 'var(--ggui-color-neutral-500, #6b7280)',
                border: isCurrent ? '2px solid var(--ggui-color-primary-500, #0ea5e9)' : '2px solid transparent',
              }}>
                {isDone ? <Icon name="check" size={14} /> : stepNum}
              </div>
              <Text
                variant="caption"
                color={isCurrent ? 'var(--ggui-color-primary-700, #0369a1)' : isDone ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-neutral-500, #6b7280)'}
                weight={isCurrent ? 'semibold' : 'normal'}
              >
                {label}
              </Text>
            </Stack>
          );
        })}
      </Row>
    </Stack>
  );
}

// ─── Step1 ────────────────────────────────────────────────────────────────────

function Step1({ name, email, nameError, emailError, onNameChange, onEmailChange }: {
  name: string; email: string; nameError: string; emailError: string;
  onNameChange: (v: string) => void; onEmailChange: (v: string) => void;
}) {
  return (
    <Stack gap={20} direction="vertical">
      <Stack gap={4} direction="vertical">
        <Text variant="h3" color="var(--ggui-color-neutral-900, #111827)">About You</Text>
        <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">Let us know who you are so we can follow up if needed.</Text>
      </Stack>
      <Input label="Full Name" placeholder="Jane Smith" value={name} onChange={onNameChange} type="text" required error={nameError} />
      <Input label="Email Address" placeholder="jane@example.com" value={email} onChange={onEmailChange} type="email" required error={emailError} />
    </Stack>
  );
}

// ─── Step2 ────────────────────────────────────────────────────────────────────

function Step2({ rating, onRatingChange, ratingOptions }: { rating: string; onRatingChange: (v: string) => void; ratingOptions: RatingOption[] }) {
  return (
    <Stack gap={20} direction="vertical">
      <Stack gap={4} direction="vertical">
        <Text variant="h3" color="var(--ggui-color-neutral-900, #111827)">Your Satisfaction</Text>
        <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">How would you rate your overall experience?</Text>
      </Stack>
      <RadioGroup label="Satisfaction Rating" value={rating} onChange={onRatingChange} options={ratingOptions} direction="vertical" />
    </Stack>
  );
}

// ─── Step3 ────────────────────────────────────────────────────────────────────

function Step3({ selected, onToggle, featureOptions }: { selected: string[]; onToggle: (value: string, checked: boolean) => void; featureOptions: FeatureOption[] }) {
  return (
    <Stack gap={20} direction="vertical">
      <Stack gap={4} direction="vertical">
        <Text variant="h3" color="var(--ggui-color-neutral-900, #111827)">Feature Interests</Text>
        <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">Which features interest you most? Select all that apply.</Text>
      </Stack>
      <Stack gap={10} direction="vertical">
        {featureOptions.map((opt) => {
          const isChecked = selected.includes(opt.value);
          return (
            <div key={opt.value} style={{
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              border: isChecked ? '1px solid var(--ggui-color-primary-400, #38bdf8)' : '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
              padding: 'var(--ggui-spacing-4, 16px)',
              background: isChecked ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'transparent',
              transition: 'border-color 200ms ease, background 200ms ease',
            }}>
              <Checkbox label={opt.label} checked={isChecked} onChange={(checked) => onToggle(opt.value, checked)} description={opt.description} />
            </div>
          );
        })}
      </Stack>
      {selected.length > 0 && (
        <Row gap={8} wrap>
          {selected.map((v) => {
            const opt = featureOptions.find((o) => o.value === v);
            return opt ? <Badge key={v} variant="primary" size="sm" pill>{opt.label}</Badge> : null;
          })}
        </Row>
      )}
    </Stack>
  );
}

// ─── Step4 ────────────────────────────────────────────────────────────────────

function Step4({ comments, onCommentsChange, maxLength }: { comments: string; onCommentsChange: (v: string) => void; maxLength: number }) {
  const remaining   = maxLength - comments.length;
  const isAtLimit   = remaining <= 0;
  const isNearLimit = remaining < 60 && !isAtLimit;
  const counterColor = isAtLimit
    ? 'var(--ggui-color-error-500, #ef4444)'
    : isNearLimit
    ? 'var(--ggui-color-warning-600, #d97706)'
    : 'var(--ggui-color-neutral-500, #6b7280)';
  const counterSuffix = remaining !== 1 ? 's' : '';

  return (
    <Stack gap={20} direction="vertical">
      <Stack gap={4} direction="vertical">
        <Text variant="h3" color="var(--ggui-color-neutral-900, #111827)">Additional Comments</Text>
        <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">Anything else you'd like to share? This field is optional.</Text>
      </Stack>
      <Stack gap={6} direction="vertical">
        <TextArea label="Your Comments" placeholder="Share your thoughts, suggestions, or feedback…" value={comments} onChange={onCommentsChange} rows={6} maxLength={maxLength} />
        <Row justify="end">
          <Text variant="caption" color={counterColor}>
            {remaining} character{counterSuffix} remaining
          </Text>
        </Row>
      </Stack>
    </Stack>
  );
}

// ─── ReviewStep ───────────────────────────────────────────────────────────────

function ReviewStep({ answers, ratingOptions, featureOptions }: { answers: SurveyAnswers; ratingOptions: RatingOption[]; featureOptions: FeatureOption[] }) {
  const ratingLabel   = ratingOptions.find((o) => o.value === answers.rating)?.label ?? '—';
  const featureLabels = answers.features.length > 0
    ? answers.features.map((v) => featureOptions.find((o) => o.value === v)?.label ?? v).join(', ')
    : 'None selected';

  const rows: { label: string; value: string }[] = [
    { label: 'Full Name',    value: answers.name     || '—' },
    { label: 'Email',        value: answers.email    || '—' },
    { label: 'Satisfaction', value: ratingLabel               },
    { label: 'Interests',    value: featureLabels             },
    { label: 'Comments',     value: answers.comments || 'No comments provided' },
  ];
  const lastIdx = rows.length - 1;

  return (
    <Stack gap={20} direction="vertical">
      <Stack gap={4} direction="vertical">
        <Text variant="h3" color="var(--ggui-color-neutral-900, #111827)">Review Your Answers</Text>
        <Text variant="body" color="var(--ggui-color-neutral-500, #6b7280)">Please review your responses before submitting.</Text>
      </Stack>
      <Stack gap={0} direction="vertical">
        {rows.map((row, i) => {
          const topRadius = 'var(--ggui-shape-radius-md, 8px) var(--ggui-shape-radius-md, 8px) 0 0';
          const btmRadius = '0 0 var(--ggui-shape-radius-md, 8px) var(--ggui-shape-radius-md, 8px)';
          const rowRadius = i === 0 ? topRadius : i === lastIdx ? btmRadius : '0';
          const rowBg = i % 2 === 0 ? 'var(--ggui-color-neutral-50, #f9fafb)' : 'transparent';
          const topBorder = i === 0 ? '1px solid var(--ggui-color-neutral-200, #e5e7eb)' : 'none';
          const isComment = row.label === 'Comments';

          return (
            <div key={row.label} style={{
              padding: 'var(--ggui-spacing-4, 16px)',
              borderRadius: rowRadius,
              background: rowBg,
              borderLeft: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
              borderRight: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
              borderTop: topBorder,
              borderBottom: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
            }}>
              <Row align="start" gap={12}>
                <div style={{ minWidth: 120, flexShrink: 0 }}>
                  <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)" weight="medium">{row.label}</Text>
                </div>
                <Text variant="body" color="var(--ggui-color-neutral-900, #111827)" weight={isComment ? 'normal' : 'semibold'}>{row.value}</Text>
              </Row>
            </div>
          );
        })}
      </Stack>
      <div style={{
        padding: 'var(--ggui-spacing-4, 16px)',
        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
        background: 'var(--ggui-color-primary-50, #f0f9ff)',
        border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
        display: 'flex', alignItems: 'center', gap: 'var(--ggui-spacing-2, 8px)',
      }}>
        <Icon name="check" size={16} color="var(--ggui-color-primary-600, #0284c7)" />
        <Text variant="caption" color="var(--ggui-color-primary-700, #0369a1)">Clicking Submit will send your responses. This action cannot be undone.</Text>
      </div>
    </Stack>
  );
}

// ─── Main Component ───────────────────────────────────────────────────────────

export default function GeneratedComponent({
  surveyTitle       = 'Customer Feedback Survey',
  surveyDescription = 'Help us improve by sharing your experience. Takes about 2 minutes.',
  ratingOptions     = DEFAULT_RATING_OPTIONS,
  featureOptions    = DEFAULT_FEATURE_OPTIONS,
  maxCommentLength  = 500,
  onSubmit,
}: Props) {
  const { motionEnabled } = useMotion();

  const [currentStep,  setCurrentStep]  = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitted,    setSubmitted]    = useState(false);

  const [name,         setName]         = useState('');
  const [email,        setEmail]        = useState('');
  const [nameTouched,  setNameTouched]  = useState(false);
  const [emailTouched, setEmailTouched] = useState(false);
  const [rating,       setRating]       = useState('');
  const [features,     setFeatures]     = useState<string[]>([]);
  const [comments,     setComments]     = useState('');

  const nameError  = nameTouched  && !name.trim()        ? 'Name is required'           : '';
  const emailError = emailTouched && !email.trim()        ? 'Email is required'
                   : emailTouched && !isValidEmail(email) ? 'Please enter a valid email' : '';

  const step1Valid = name.trim().length > 0 && email.trim().length > 0 && isValidEmail(email);
  const step2Valid = rating !== '';
  const showReview = currentStep === TOTAL_STEPS + 1;
  const canAdvance = currentStep === 1 ? step1Valid : currentStep === 2 ? step2Valid : true;
  const progressStep = showReview ? TOTAL_STEPS : currentStep;
  const stepFraction = showReview ? 'Review & Submit' : (currentStep + ' / ' + TOTAL_STEPS);
  const headerBg = 'linear-gradient(135deg, var(--ggui-color-primary-600, #0284c7), var(--ggui-color-primary-800, #075985))';
  const headerRadius = 'var(--ggui-shape-radius-xl, 16px) var(--ggui-shape-radius-xl, 16px) 0 0';

  const handleNameChange = useCallback((v: string) => { setName(v); setNameTouched(true); }, []);
  const handleEmailChange = useCallback((v: string) => { setEmail(v); setEmailTouched(true); }, []);

  const handleNext = useCallback(() => {
    if (currentStep === 1) {
      setNameTouched(true);
      setEmailTouched(true);
      if (!step1Valid) return;
    }
    setCurrentStep((s) => s + 1);
  }, [currentStep, step1Valid]);

  const handleBack = useCallback(() => { setCurrentStep((s) => Math.max(1, s - 1)); }, []);

  const handleToggleFeature = useCallback((value: string, checked: boolean) => {
    setFeatures((prev) => checked ? [...prev, value] : prev.filter((v) => v !== value));
  }, []);

  const handleSubmit = useCallback(async () => {
    const answers: SurveyAnswers = { name, email, rating, features, comments };
    setIsSubmitting(true);
    try { await onSubmit?.(answers); setSubmitted(true); }
    finally { setIsSubmitting(false); }
  }, [name, email, rating, features, comments, onSubmit]);

  if (submitted) {
    return (
      <Container maxWidth="md" center>
        <MotionKeyframes />
        <Card padding={40} shadow="lg">
          <Stack gap={24} direction="vertical" align="center">
            <div style={{
              width: 72, height: 72,
              borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
              background: 'var(--ggui-color-success-500, #22c55e)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              animation: motionEnabled ? animation.scaleIn : 'none',
            }}>
              <Icon name="check" size={36} color="var(--ggui-color-neutral-50, #f9fafb)" />
            </div>
            <Stack gap={8} direction="vertical" align="center">
              <Text variant="h2" align="center" color="var(--ggui-color-neutral-900, #111827)">Thank You!</Text>
              <Text variant="body" align="center" color="var(--ggui-color-neutral-500, #6b7280)">
                Your feedback has been submitted. We appreciate your time and will use your responses to improve our product.
              </Text>
            </Stack>
          </Stack>
        </Card>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" center>
      <MotionKeyframes />
      <Stack gap={0} direction="vertical">

        <div style={{ padding: 'var(--ggui-spacing-6, 24px)', background: headerBg, borderRadius: headerRadius }}>
          <Stack gap={4} direction="vertical">
            <Text variant="h2" color="var(--ggui-color-neutral-50, #f9fafb)" weight="bold">{surveyTitle}</Text>
            <Text variant="body" color="var(--ggui-color-primary-100, #e0f2fe)">{surveyDescription}</Text>
          </Stack>
        </div>

        <Card padding={32} shadow="lg" border>
          <Stack gap={28} direction="vertical">

            <ProgressHeader currentStep={progressStep} totalSteps={TOTAL_STEPS} stepLabels={STEP_LABELS} />

            <Divider margin={0} />

            <div key={currentStep} style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
              {currentStep === 1 && <Step1 name={name} email={email} nameError={nameError} emailError={emailError} onNameChange={handleNameChange} onEmailChange={handleEmailChange} />}
              {currentStep === 2 && <Step2 rating={rating} onRatingChange={setRating} ratingOptions={ratingOptions} />}
              {currentStep === 3 && <Step3 selected={features} onToggle={handleToggleFeature} featureOptions={featureOptions} />}
              {currentStep === 4 && <Step4 comments={comments} onCommentsChange={setComments} maxLength={maxCommentLength} />}
              {showReview && <ReviewStep answers={{ name, email, rating, features, comments }} ratingOptions={ratingOptions} featureOptions={featureOptions} />}
            </div>

            <Divider margin={0} />

            <Row justify="between" align="center">
              {currentStep > 1
                ? <Button variant="outline" onClick={handleBack} leftIcon={<Icon name="chevron-left" size={16} />} disabled={isSubmitting}>Back</Button>
                : <div />
              }
              <Row gap={12} align="center">
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{stepFraction}</Text>
                {!showReview ? (
                  currentStep < TOTAL_STEPS
                    ? <Button variant="primary" onClick={handleNext} disabled={!canAdvance} rightIcon={<Icon name="chevron-right" size={16} />}>Next</Button>
                    : <Button variant="primary" onClick={handleNext} rightIcon={<Icon name="chevron-right" size={16} />}>Review</Button>
                ) : (
                  <Button
                    variant="primary"
                    onClick={handleSubmit}
                    loading={isSubmitting}
                    disabled={isSubmitting}
                    leftIcon={!isSubmitting ? <Icon name="check" size={16} /> : undefined}
                  >
                    {isSubmitting ? 'Submitting…' : 'Submit Survey'}
                  </Button>
                )}
              </Row>
            </Row>

          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import { useState, useCallback } from 'react';
import {
  Container, Card, Stack, Row, Text, Button, Input,
  Select, Badge, Icon, Spacer, MotionKeyframes, useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

type Priority = 'low' | 'medium' | 'high';
type ColumnId = 'todo' | 'inprogress' | 'done';

interface Task {
  id: string;
  title: string;
  priority: Priority;
  assignee: string;
  dueDate?: string;
  column: ColumnId;
}

interface Props {
  initialTasks?: Task[];
  onTaskUpdate?: (tasks: Task[]) => void;
}

const COLUMNS: { id: ColumnId; label: string; accentColor: string; headerBg: string }[] = [
  { id: 'todo', label: 'To Do', accentColor: 'var(--ggui-color-neutral-500, #6b7280)', headerBg: 'var(--ggui-color-neutral-100, #f3f4f6)' },
  { id: 'inprogress', label: 'In Progress', accentColor: 'var(--ggui-color-primary-600, #0284c7)', headerBg: 'var(--ggui-color-primary-50, #f0f9ff)' },
  { id: 'done', label: 'Done', accentColor: 'var(--ggui-color-success-600, #16a34a)', headerBg: 'var(--ggui-color-neutral-50, #f9fafb)' },
];

const COLUMN_OPTIONS: { value: string; label: string }[] = [
  { value: 'todo', label: 'To Do' },
  { value: 'inprogress', label: 'In Progress' },
  { value: 'done', label: 'Done' },
];

const PRIORITY_OPTIONS: { value: string; label: string }[] = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

const PRIORITY_BADGE_VARIANT: Record<Priority, 'success' | 'warning' | 'error'> = {
  low: 'success',
  medium: 'warning',
  high: 'error',
};

const DEFAULT_TASKS: Task[] = [
  { id: '1', title: 'Design homepage wireframes', priority: 'high', assignee: 'Alice', dueDate: '2025-08-01', column: 'todo' },
  { id: '2', title: 'Set up CI/CD pipeline', priority: 'medium', assignee: 'Bob', dueDate: '2025-07-28', column: 'todo' },
  { id: '3', title: 'Write unit tests for auth', priority: 'low', assignee: 'Carol', column: 'inprogress' },
  { id: '4', title: 'API integration – payments', priority: 'high', assignee: 'Dave', dueDate: '2025-07-25', column: 'inprogress' },
  { id: '5', title: 'Update README documentation', priority: 'low', assignee: 'Eve', column: 'done' },
  { id: '6', title: 'Accessibility audit', priority: 'medium', assignee: 'Frank', dueDate: '2025-07-20', column: 'done' },
];

let idCounter = 100;
function generateId(): string {
  idCounter += 1;
  return 'task-' + String(idCounter);
}

function getInitials(name: string): string {
  return name.split(' ').map((n) => n[0]).join('').toUpperCase().slice(0, 2);
}

function formatDate(iso: string): string {
  return new Date(iso + 'T00:00:00').toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
}

function isOverdue(iso: string): boolean {
  return new Date(iso + 'T00:00:00') < new Date(new Date().toDateString());
}

function Avatar({ name }: { name: string }) {
  return (
    <div title={name} style={{ width: 28, height: 28, borderRadius: 'var(--ggui-shape-radius-full, 9999px)', background: 'var(--ggui-color-primary-100, #e0f2fe)', border: '2px solid var(--ggui-color-primary-200, #bae6fd)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 'var(--ggui-font-size-xs, 12px)', fontWeight: 'var(--ggui-font-weight-semibold, 600)', color: 'var(--ggui-color-primary-700, #0369a1)', flexShrink: 0 }}>
      {getInitials(name)}
    </div>
  );
}

interface TaskCardProps {
  task: Task;
  currentColumnId: ColumnId;
  onMove: (taskId: string, toColumn: ColumnId) => void;
  onEdit: (taskId: string, updates: Partial<Task>) => void;
  motionEnabled: boolean;
}

function TaskCard({ task, currentColumnId, onMove, onEdit, motionEnabled }: TaskCardProps) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title);
  const [editPriority, setEditPriority] = useState<string>(task.priority);
  const [editAssignee, setEditAssignee] = useState(task.assignee);
  const [editDueDate, setEditDueDate] = useState(task.dueDate ?? '');
  const [moveTarget, setMoveTarget] = useState<string>(currentColumnId);

  const handleSaveEdit = () => {
    if (!editTitle.trim()) return;
    onEdit(task.id, { title: editTitle.trim(), priority: editPriority as Priority, assignee: editAssignee.trim() || task.assignee, dueDate: editDueDate || undefined });
    setIsEditing(false);
  };

  const handleCancelEdit = () => {
    setEditTitle(task.title);
    setEditPriority(task.priority);
    setEditAssignee(task.assignee);
    setEditDueDate(task.dueDate ?? '');
    setIsEditing(false);
  };

  const handleMove = () => {
    if (moveTarget && moveTarget !== currentColumnId) {
      onMove(task.id, moveTarget as ColumnId);
    }
  };

  const overdue = task.dueDate ? isOverdue(task.dueDate) && currentColumnId !== 'done' : false;

  if (isEditing) {
    return (
      <Card padding={12} shadow="md" border style={{ animation: motionEnabled ? animation.scaleIn : 'none', borderColor: 'var(--ggui-color-primary-200, #bae6fd)' }}>
        <Stack direction="vertical" gap={8}>
          <Input label="Title" value={editTitle} onChange={setEditTitle} placeholder="Task title" />
          <Select label="Priority" value={editPriority} onChange={setEditPriority} options={PRIORITY_OPTIONS} />
          <Input label="Assignee" value={editAssignee} onChange={setEditAssignee} placeholder="Name" />
          <Input label="Due Date (YYYY-MM-DD)" type="text" value={editDueDate} onChange={setEditDueDate} placeholder="YYYY-MM-DD" />
          <Row gap={6} justify="end">
            <Button variant="ghost" size="sm" onClick={handleCancelEdit}>Cancel</Button>
            <Button variant="primary" size="sm" onClick={handleSaveEdit} disabled={!editTitle.trim()}>Save</Button>
          </Row>
        </Stack>
      </Card>
    );
  }

  return (
    <Card padding={12} shadow="sm" border style={{ animation: motionEnabled ? animation.slideInUp : 'none', transition: 'box-shadow 200ms cubic-bezier(0.4,0,0.2,1)' }}>
      <Stack direction="vertical" gap={8}>
        <Row gap={6} align="start">
          <div style={{ flex: 1 }} onDoubleClick={() => setIsEditing(true)} title="Double-click to edit">
            <Text variant="body" weight="medium" style={{ wordBreak: 'break-word', color: currentColumnId === 'done' ? 'var(--ggui-color-neutral-500, #6b7280)' : 'var(--ggui-color-neutral-900, #111827)', textDecoration: currentColumnId === 'done' ? 'line-through' : 'none' }}>
              {task.title}
            </Text>
          </div>
          <Button variant="ghost" size="xs" onClick={() => setIsEditing(true)} leftIcon={<Icon name="settings" size={13} />} />
        </Row>
        <Row gap={6} align="center">
          <Badge variant={PRIORITY_BADGE_VARIANT[task.priority]} size="sm" pill>
            {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
          </Badge>
          <Spacer />
          <Avatar name={task.assignee} />
        </Row>
        {task.dueDate && (
          <Row gap={4} align="center">
            <div style={{ width: 8, height: 8, borderRadius: 'var(--ggui-shape-radius-full, 9999px)', background: overdue ? 'var(--ggui-color-error-500, #ef4444)' : 'var(--ggui-color-neutral-300, #d1d5db)', flexShrink: 0 }} />
            <Text variant="caption" style={{ color: overdue ? 'var(--ggui-color-error-500, #ef4444)' : 'var(--ggui-color-neutral-500, #6b7280)', fontWeight: overdue ? 'var(--ggui-font-weight-semibold, 600)' : 'var(--ggui-font-weight-normal, 400)' }}>
              {formatDate(task.dueDate)}{overdue ? ' · Overdue' : ''}
            </Text>
          </Row>
        )}
        <Row gap={6} align="center">
          <div style={{ flex: 1 }}>
            <Select label="Move to" value={moveTarget} onChange={setMoveTarget} options={COLUMN_OPTIONS} />
          </div>
          <Button variant="outline" size="sm" onClick={handleMove} disabled={moveTarget === currentColumnId} rightIcon={<Icon name="chevron-right" size={13} />}>
            Move
          </Button>
        </Row>
      </Stack>
    </Card>
  );
}

interface AddTaskFormProps {
  onAdd: (title: string, priority: Priority, assignee: string, dueDate: string) => void;
  onCancel: () => void;
  motionEnabled: boolean;
}

function AddTaskForm({ onAdd, onCancel, motionEnabled }: AddTaskFormProps) {
  const [title, setTitle] = useState('');
  const [priority, setPriority] = useState<string>('medium');
  const [assignee, setAssignee] = useState('');
  const [dueDate, setDueDate] = useState('');

  const handleAdd = () => {
    if (!title.trim()) return;
    onAdd(title.trim(), priority as Priority, assignee.trim() || 'Unassigned', dueDate);
  };

  return (
    <Card padding={12} shadow="md" border style={{ animation: motionEnabled ? animation.slideInDown : 'none', borderColor: 'var(--ggui-color-primary-300, #7dd3fc)', background: 'var(--ggui-color-primary-50, #f0f9ff)' }}>
      <Stack direction="vertical" gap={8}>
        <Input label="Task title" placeholder="What needs to be done?" value={title} onChange={setTitle} required />
        <Row gap={6}>
          <div style={{ flex: 1 }}>
            <Select label="Priority" value={priority} onChange={setPriority} options={PRIORITY_OPTIONS} />
          </div>
          <div style={{ flex: 1 }}>
            <Input label="Assignee" placeholder="Name" value={assignee} onChange={setAssignee} />
          </div>
        </Row>
        <Input label="Due Date (YYYY-MM-DD)" placeholder="YYYY-MM-DD" value={dueDate} onChange={setDueDate} type="text" />
        <Row gap={6} justify="end">
          <Button variant="ghost" size="sm" onClick={onCancel}>Cancel</Button>
          <Button variant="primary" size="sm" onClick={handleAdd} disabled={!title.trim()} leftIcon={<Icon name="plus" size={14} />}>Add Task</Button>
        </Row>
      </Stack>
    </Card>
  );
}

interface KanbanColumnProps {
  columnDef: (typeof COLUMNS)[number];
  tasks: Task[];
  onMove: (taskId: string, toColumn: ColumnId) => void;
  onEdit: (taskId: string, updates: Partial<Task>) => void;
  onAddTask: (title: string, priority: Priority, assignee: string, dueDate: string) => void;
  motionEnabled: boolean;
}

function KanbanColumn({ columnDef, tasks, onMove, onEdit, onAddTask, motionEnabled }: KanbanColumnProps) {
  const [showAddForm, setShowAddForm] = useState(false);

  const handleAdd = (title: string, priority: Priority, assignee: string, dueDate: string) => {
    onAddTask(title, priority, assignee, dueDate);
    setShowAddForm(false);
  };

  return (
    <div style={{ flex: '1 1 0', minWidth: 280, maxWidth: 380, display: 'flex', flexDirection: 'column' }}>
      <div style={{ padding: 'var(--ggui-spacing-4, 16px)', background: columnDef.headerBg, borderRadius: 'var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) 0 0', borderTop: '3px solid ' + columnDef.accentColor, borderLeft: '1px solid var(--ggui-color-neutral-200, #e5e7eb)', borderRight: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' }}>
        <Row gap={8} align="center">
          <Text variant="label" weight="semibold" style={{ color: columnDef.accentColor, fontSize: 'var(--ggui-font-size-sm, 14px)', textTransform: 'uppercase', letterSpacing: '0.06em' }}>
            {columnDef.label}
          </Text>
          <Spacer />
          <div style={{ minWidth: 22, height: 22, borderRadius: 'var(--ggui-shape-radius-full, 9999px)', background: columnDef.accentColor, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '0 6px' }}>
            <Text variant="caption" style={{ color: 'var(--ggui-color-neutral-50, #f9fafb)', fontWeight: 'var(--ggui-font-weight-bold, 700)', fontSize: 'var(--ggui-font-size-xs, 12px)' }}>
              {tasks.length}
            </Text>
          </div>
        </Row>
      </div>

      <div style={{ flex: 1, padding: 'var(--ggui-spacing-2, 8px)', background: 'var(--ggui-color-neutral-100, #f3f4f6)', borderLeft: '1px solid var(--ggui-color-neutral-200, #e5e7eb)', borderRight: '1px solid var(--ggui-color-neutral-200, #e5e7eb)', minHeight: 120, display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-2, 8px)' }}>
        {tasks.length === 0 && !showAddForm && (
          <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 'var(--ggui-spacing-8, 32px) 0' }}>
            <Text variant="caption" style={{ color: 'var(--ggui-color-neutral-300, #d1d5db)', textAlign: 'center', fontStyle: 'italic' }}>
              No tasks yet
            </Text>
          </div>
        )}
        {tasks.map((task, i) => (
          <div key={task.id} style={{ animation: motionEnabled ? animation.slideInUp : 'none', animationDelay: motionEnabled ? (String(i * 40) + 'ms') : '0ms' }}>
            <TaskCard task={task} currentColumnId={columnDef.id} onMove={onMove} onEdit={onEdit} motionEnabled={motionEnabled} />
          </div>
        ))}
        {showAddForm && (
          <AddTaskForm onAdd={handleAdd} onCancel={() => setShowAddForm(false)} motionEnabled={motionEnabled} />
        )}
      </div>

      <div style={{ padding: 'var(--ggui-spacing-2, 8px)', background: 'var(--ggui-color-neutral-100, #f3f4f6)', borderRadius: '0 0 var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px)', borderBottom: '1px solid var(--ggui-color-neutral-200, #e5e7eb)', borderLeft: '1px solid var(--ggui-color-neutral-200, #e5e7eb)', borderRight: '1px solid var(--ggui-color-neutral-200, #e5e7eb)' }}>
        {!showAddForm && (
          <Button variant="ghost" size="sm" fullWidth onClick={() => setShowAddForm(true)} leftIcon={<Icon name="plus" size={14} />} style={{ color: columnDef.accentColor }}>
            Add Task
          </Button>
        )}
      </div>
    </div>
  );
}

function SummaryBar({ tasks }: { tasks: Task[] }) {
  const total = tasks.length;
  const done = tasks.filter((t) => t.column === 'done').length;
  const inProgress = tasks.filter((t) => t.column === 'inprogress').length;
  const todo = tasks.filter((t) => t.column === 'todo').length;
  const pct = total === 0 ? 0 : Math.round((done / total) * 100);
  const highPriority = tasks.filter((t) => t.priority === 'high' && t.column !== 'done').length;

  const stats = [
    { label: 'Total', value: total, color: 'var(--ggui-color-neutral-700, #374151)' },
    { label: 'To Do', value: todo, color: 'var(--ggui-color-neutral-500, #6b7280)' },
    { label: 'In Progress', value: inProgress, color: 'var(--ggui-color-primary-600, #0284c7)' },
    { label: 'Completed', value: done, color: 'var(--ggui-color-success-600, #16a34a)' },
    { label: 'High Priority', value: highPriority, color: highPriority > 0 ? 'var(--ggui-color-error-500, #ef4444)' : 'var(--ggui-color-neutral-500, #6b7280)' },
  ];

  return (
    <Card padding={16} shadow="sm" border>
      <Stack direction="vertical" gap={10}>
        <Row gap={24} wrap align="center">
          {stats.map(({ label, value, color }) => (
            <Stack key={label} direction="vertical" gap={2} align="center">
              <Text variant="h3" style={{ color, fontWeight: 'var(--ggui-font-weight-bold, 700)', fontSize: 'var(--ggui-font-size-xl, 20px)', lineHeight: '1' }}>
                {value}
              </Text>
              <Text variant="caption" style={{ color: 'var(--ggui-color-neutral-500, #6b7280)', whiteSpace: 'nowrap' }}>
                {label}
              </Text>
            </Stack>
          ))}
          <Spacer />
          <Text variant="caption" weight="semibold" style={{ color: 'var(--ggui-color-neutral-700, #374151)' }}>
            {pct}% Complete
          </Text>
        </Row>
        <div style={{ height: 6, borderRadius: 'var(--ggui-shape-radius-full, 9999px)', background: 'var(--ggui-color-neutral-200, #e5e7eb)', overflow: 'hidden' }}>
          <div style={{ height: '100%', width: String(pct) + '%', borderRadius: 'var(--ggui-shape-radius-full, 9999px)', background: pct === 100 ? 'var(--ggui-color-success-500, #22c55e)' : 'var(--ggui-color-primary-500, #0ea5e9)', transition: 'width 400ms cubic-bezier(0.4,0,0.2,1)' }} />
        </div>
      </Stack>
    </Card>
  );
}

export default function GeneratedComponent({ initialTasks = DEFAULT_TASKS, onTaskUpdate }: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const { motionEnabled } = useMotion();

  const updateTasks = useCallback((updater: (prev: Task[]) => Task[]) => {
    setTasks((prev) => {
      const next = updater(prev);
      onTaskUpdate?.(next);
      return next;
    });
  }, [onTaskUpdate]);

  const handleMove = useCallback((taskId: string, toColumn: ColumnId) => {
    updateTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: toColumn } : t)));
  }, [updateTasks]);

  const handleEdit = useCallback((taskId: string, updates: Partial<Task>) => {
    updateTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, ...updates } : t)));
  }, [updateTasks]);

  const handleAddTask = useCallback((columnId: ColumnId, title: string, priority: Priority, assignee: string, dueDate: string) => {
    const newTask: Task = { id: generateId(), title, priority, assignee, dueDate: dueDate || undefined, column: columnId };
    updateTasks((prev) => [...prev, newTask]);
  }, [updateTasks]);

  return (
    <Container maxWidth="full" padding={24}>
      <MotionKeyframes />
      <Stack direction="vertical" gap={20}>
        <Row gap={10} align="center">
          <Text variant="h1" weight="bold" style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)', color: 'var(--ggui-color-neutral-900, #111827)' }}>
            Task Board
          </Text>
          <Badge variant="primary" size="sm" pill>Kanban</Badge>
        </Row>
        <SummaryBar tasks={tasks} />
        <div style={{ display: 'flex', flexDirection: 'row', gap: 'var(--ggui-spacing-4, 16px)', alignItems: 'flex-start', overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          {COLUMNS.map((col) => {
            const colTasks = tasks.filter((t) => t.column === col.id);
            return (
              <KanbanColumn
                key={col.id}
                columnDef={col}
                tasks={colTasks}
                onMove={handleMove}
                onEdit={handleEdit}
                onAddTask={(title, priority, assignee, dueDate) => handleAddTask(col.id, title, priority, assignee, dueDate)}
                motionEnabled={motionEnabled}
              />
            );
          })}
        </div>
      </Stack>
    </Container>
  );
}

