import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  TextArea,
  Button,
  RadioGroup,
  Checkbox,
  Divider,
  Icon,
  Box,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface SurveyData {
  name: string;
  email: string;
  rating: string;
  interests: string[];
  comments: string;
}

interface Props {
  ratingLabels?: string[];
  featureOptions?: string[];
  onSubmit: (data: SurveyData) => void;
}

const DEFAULT_RATING_LABELS = ['Poor', 'Fair', 'Average', 'Good', 'Excellent'];
const DEFAULT_FEATURES = ['Ease of Use', 'Performance', 'UI Design', 'Customer Support', 'Documentation'];

export default function SurveyForm({
  ratingLabels = DEFAULT_RATING_LABELS,
  featureOptions = DEFAULT_FEATURES,
  onSubmit
}: Props) {
  const [step, setStep] = useState(0);
  const [formData, setFormData] = useState<SurveyData>({
    name: '',
    email: '',
    rating: '',
    interests: [],
    comments: '',
  });

  const { motionEnabled } = useMotion();

  const totalSteps = 5; // 4 input steps + 1 review step

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  const errors = useMemo(() => {
    const errs: Record<string, string> = {};
    if (!formData.name.trim()) errs.name = 'Name is required';
    if (!formData.email.trim()) {
      errs.email = 'Email is required';
    } else if (!emailRegex.test(formData.email)) {
      errs.email = 'Invalid email format';
    }
    return errs;
  }, [formData.name, formData.email]);

  const isStepValid = () => {
    switch (step) {
      case 0:
        return !!formData.name.trim() && !!formData.email.trim() && !errors.email;
      case 1:
        return !!formData.rating;
      case 2:
        return formData.interests.length > 0;
      case 3:
        return true; // Comments are optional
      default:
        return true;
    }
  };

  const handleNext = () => {
    if (step < totalSteps - 1) {
      setStep(s => s + 1);
    }
  };

  const handleBack = () => {
    if (step > 0) {
      setStep(s => s - 1);
    }
  };

  const handleSubmit = () => {
    onSubmit(formData);
  };

  const toggleInterest = (interest: string) => {
    setFormData(prev => {
      const interests = prev.interests.includes(interest)
        ? prev.interests.filter(i => i !== interest)
        : [...prev.interests, interest];
      return { ...prev, interests };
    });
  };

  const ratingOptions = ratingLabels.slice(0, 5).map((label, index) => ({
    value: String(index + 1),
    label: (index + 1) + ' - ' + label,
  }));

  const progressValue = ((step + 1) / totalSteps) * 100;
  const progressWidth = String(progressValue) + '%';

  return (
    <Container maxWidth="sm">
      <MotionKeyframes />
      <Card padding="var(--ggui-spacing-6)" shadow="md">
        <Stack gap={24} role="form" aria-label="Survey Form">
          {/* Progress Section */}
          <Stack gap={8}>
            <Row justify="between" align="center">
              <Text variant="caption" weight="medium" color="var(--ggui-color-neutral-500)">
                Step {String(step + 1)} of {String(totalSteps)}
              </Text>
              <Text variant="caption" weight="bold" color="var(--ggui-color-primary-600)">
                {String(Math.round(progressValue)) + '%'}
              </Text>
            </Row>
            <div style={{
              height: 8,
              width: '100%',
              backgroundColor: 'var(--ggui-color-neutral-200)',
              borderRadius: 'var(--ggui-shape-radius-full)',
              overflow: 'hidden'
            }}>
              <div style={{
                height: '100%',
                width: progressWidth,
                backgroundColor: 'var(--ggui-color-primary-600)',
                transition: transition.normal,
                borderRadius: 'var(--ggui-shape-radius-full)'
              }} />
            </div>
          </Stack>

          <Divider />

          {/* Form Content */}
          <div style={{
            minHeight: 320,
            animation: motionEnabled ? animation.fadeIn : 'none'
          }} key={String(step)}>
            {step === 0 && (
              <Stack gap={20}>
                <Text variant="h3">Basic Information</Text>
                <Input
                  label="Full Name"
                  placeholder="John Doe"
                  value={formData.name}
                  onChange={(val) => setFormData({ ...formData, name: val })}
                  error={formData.name ? errors.name : undefined}
                  required
                />
                <Input
                  label="Email Address"
                  type="email"
                  placeholder="john@example.com"
                  value={formData.email}
                  onChange={(val) => setFormData({ ...formData, email: val })}
                  error={formData.email ? errors.email : undefined}
                  required
                />
              </Stack>
            )}

            {step === 1 && (
              <Stack gap={20}>
                <Text variant="h3">Satisfaction Rating</Text>
                <Text color="var(--ggui-color-neutral-600)">
                  How satisfied are you with our service overall?
                </Text>
                <RadioGroup
                  value={formData.rating}
                  onChange={(val) => setFormData({ ...formData, rating: val })}
                  options={ratingOptions}
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Text variant="h3">Feature Interests</Text>
                  <Text variant="caption" color="var(--ggui-color-neutral-500)">
                    Select all that apply
                  </Text>
                </Stack>
                <Stack gap={12}>
                  {featureOptions.map(option => (
                    <Checkbox
                      key={option}
                      label={option}
                      checked={formData.interests.includes(option)}
                      onChange={() => toggleInterest(option)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={20}>
                <Text variant="h3">Additional Comments</Text>
                <TextArea
                  label="Feedback (Optional)"
                  placeholder="Tell us what you think..."
                  value={formData.comments}
                  onChange={(val) => setFormData({ ...formData, comments: val })}
                  maxLength={500}
                  rows={6}
                  helperText={String(formData.comments.length) + '/500 characters'}
                />
              </Stack>
            )}

            {step === 4 && (
              <Stack gap={20}>
                <Text variant="h3">Review Your Answers</Text>
                <Card padding="var(--ggui-spacing-4)" border background="var(--ggui-color-neutral-50)">
                  <Stack gap={16}>
                    <Row justify="between">
                      <Text weight="bold" color="var(--ggui-color-neutral-500)">Name</Text>
                      <Text>{formData.name}</Text>
                    </Row>
                    <Divider />
                    <Row justify="between">
                      <Text weight="bold" color="var(--ggui-color-neutral-500)">Email</Text>
                      <Text>{formData.email}</Text>
                    </Row>
                    <Divider />
                    <Row justify="between">
                      <Text weight="bold" color="var(--ggui-color-neutral-500)">Rating</Text>
                      <Text>{ratingLabels[parseInt(formData.rating) - 1]}</Text>
                    </Row>
                    <Divider />
                    <Stack gap={8}>
                      <Text weight="bold" color="var(--ggui-color-neutral-500)">Interests</Text>
                      <Row gap={8} wrap>
                        {formData.interests.map(i => (
                          <Box
                            key={i}
                            paddingX="var(--ggui-spacing-2)"
                            paddingY="var(--ggui-spacing-1)"
                            borderRadius="var(--ggui-shape-radius-full)"
                            background="var(--ggui-color-primary-100)"
                          >
                            <Text variant="caption" color="var(--ggui-color-primary-700)" weight="semibold">
                              {i}
                            </Text>
                          </Box>
                        ))}
                      </Row>
                    </Stack>
                    {formData.comments && (
                      <>
                        <Divider />
                        <Stack gap={8}>
                          <Text weight="bold" color="var(--ggui-color-neutral-500)">Comments</Text>
                          <Text variant="caption">{formData.comments}</Text>
                        </Stack>
                      </>
                    )}
                  </Stack>
                </Card>
              </Stack>
            )}
          </div>

          <Divider />

          {/* Footer Navigation */}
          <Row justify="between">
            <Button
              variant="outline"
              onClick={handleBack}
              disabled={step === 0}
              leftIcon={<Icon name="chevron-left" size={16} />}
            >
              Back
            </Button>

            {step === totalSteps - 1 ? (
              <Button
                variant="primary"
                onClick={handleSubmit}
                rightIcon={<Icon name="check" size={16} />}
              >
                Submit Survey
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={!isStepValid()}
                rightIcon={<Icon name="chevron-right" size={16} />}
              >
                Next
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Button,
  Input,
  Select,
  Badge,
  Icon,
  Divider,
  Box,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

/**
 * TYPES
 */
export type TaskPriority = 'low' | 'medium' | 'high';
export type TaskStatus = 'todo' | 'inprogress' | 'done';

export interface Task {
  id: string;
  title: string;
  priority: TaskPriority;
  status: TaskStatus;
  assignee?: string;
  dueDate?: string;
}

interface Props {
  initialTasks?: Task[];
  onTaskUpdate?: (updatedTasks: Task[], action: { type: 'create' | 'move' | 'edit' | 'delete'; task: Task }) => void;
  boardTitle?: string;
}

/**
 * CONSTANTS
 */
const STATUS_LABELS: Record<TaskStatus, string> = {
  todo: 'To Do',
  inprogress: 'In Progress',
  done: 'Done'
};

const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' }
];

/**
 * SUB-COMPONENTS
 */

const PriorityBadge = ({ priority }: { priority: TaskPriority }) => {
  const variantMap: Record<TaskPriority, 'info' | 'warning' | 'error'> = {
    low: 'info',
    medium: 'warning',
    high: 'error'
  };

  return (
    <Badge variant={variantMap[priority]} size="sm">
      {priority.toUpperCase()}
    </Badge>
  );
};

const TaskCard = ({
  task,
  onMove,
  onEdit
}: {
  task: Task;
  onMove: (newStatus: TaskStatus) => void;
  onEdit: (updatedTask: Task) => void;
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editValue, setEditValue] = useState(task.title);

  const handleTitleSubmit = () => {
    if (editValue.trim() && editValue !== task.title) {
      onEdit({ ...task, title: editValue });
    }
    setIsEditing(false);
  };

  const statusOptions = (Object.keys(STATUS_LABELS) as TaskStatus[])
    .filter(s => s !== task.status)
    .map(s => ({ value: s, label: STATUS_LABELS[s] }));

  return (
    <Card shadow="sm" border>
      <Stack gap={12}>
        <Row justify="between" align="start">
          <PriorityBadge priority={task.priority} />
          <Row gap={4}>
            {isEditing ? (
               <Button variant="ghost" size="xs" onClick={handleTitleSubmit}>
                 <Icon name="check" size={14} />
               </Button>
            ) : (
              <Button variant="ghost" size="xs" onClick={() => setIsEditing(true)}>
                <Icon name="settings" size={14} />
              </Button>
            )}
          </Row>
        </Row>

        {isEditing ? (
          <Input
            label="Edit Task Title"
            value={editValue}
            onChange={setEditValue}
            placeholder="Task title..."
          />
        ) : (
          <Text
            variant="body"
            weight="medium"
            onDoubleClick={() => setIsEditing(true)}
            style={{ cursor: 'pointer' }}
          >
            {task.title}
          </Text>
        )}

        <Row wrap gap={8} align="center">
          {task.assignee && (
            <Row gap={4} align="center">
              <Box
                padding={0}
                borderRadius="full"
                background="var(--ggui-color-primary-100)"
                style={{ 
                  width: '20px', 
                  height: '20px', 
                  display: 'flex', 
                  alignItems: 'center', 
                  justifyContent: 'center' 
                }}
              >
                <Text variant="caption" color="var(--ggui-color-primary-700)" weight="bold">
                  {task.assignee.substring(0, 1).toUpperCase()}
                </Text>
              </Box>
              <Text variant="caption" color="var(--ggui-color-neutral-500)">
                {task.assignee}
              </Text>
            </Row>
          )}

          {task.dueDate && (
            <Text variant="caption" color="var(--ggui-color-neutral-500)">
              📅 {task.dueDate}
            </Text>
          )}
        </Row>

        <Divider margin={4} />

        <Row align="center" justify="between" wrap>
          <Text variant="caption" color="var(--ggui-color-neutral-500)">Move to:</Text>
          <Row gap={4}>
            {statusOptions.map(opt => (
              <Button
                key={opt.value}
                variant="outline"
                size="xs"
                onClick={() => onMove(opt.value as TaskStatus)}
              >
                {opt.label}
              </Button>
            ))}
          </Row>
        </Row>
      </Stack>
    </Card>
  );
};

const AddTaskForm = ({
  onAdd,
  onCancel
}: {
  onAdd: (task: Partial<Task>) => void;
  onCancel: () => void;
}) => {
  const [title, setTitle] = useState('');
  const [priority, setPriority] = useState<TaskPriority>('medium');

  const handleSubmit = () => {
    if (!title.trim()) return;
    onAdd({ title, priority });
    setTitle('');
  };

  return (
    <Card border background="var(--ggui-color-neutral-50)">
      <Stack gap={12}>
        <Input
          label="New Task Title"
          value={title}
          onChange={setTitle}
          placeholder="What needs to be done?"
          required
        />
        <Select
          label="Priority"
          value={priority}
          onChange={(v) => setPriority(v as TaskPriority)}
          options={PRIORITY_OPTIONS}
        />
        <Row gap={8} justify="end">
          <Button variant="ghost" size="sm" onClick={onCancel}>Cancel</Button>
          <Button variant="primary" size="sm" onClick={handleSubmit}>Add Task</Button>
        </Row>
      </Stack>
    </Card>
  );
};

/**
 * MAIN COMPONENT
 */
export default function KanbanBoard({
  initialTasks = [],
  onTaskUpdate,
  boardTitle = "Project Board"
}: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [addingTo, setAddingTo] = useState<TaskStatus | null>(null);
  const { motionEnabled } = useMotion();

  const counts = useMemo(() => {
    const total = tasks.length;
    const completed = tasks.filter(t => t.status === 'done').length;
    return { total, completed };
  }, [tasks]);

  const handleUpdate = (updatedTasks: Task[], action: { type: 'create' | 'move' | 'edit' | 'delete'; task: Task }) => {
    setTasks(updatedTasks);
    onTaskUpdate?.(updatedTasks, action);
  };

  const addTask = (status: TaskStatus, taskData: Partial<Task>) => {
    const newTask: Task = {
      id: Math.random().toString(36).substring(2, 9),
      title: taskData.title || 'New Task',
      priority: taskData.priority || 'medium',
      status: status,
      assignee: 'You'
    };
    const nextTasks = [...tasks, newTask];
    handleUpdate(nextTasks, { type: 'create', task: newTask });
    setAddingTo(null);
  };

  const moveTask = (task: Task, newStatus: TaskStatus) => {
    const updatedTask: Task = { ...task, status: newStatus };
    const nextTasks = tasks.map(t => (t.id === task.id ? updatedTask : t));
    handleUpdate(nextTasks, { type: 'move', task: updatedTask });
  };

  const editTask = (task: Task) => {
    const nextTasks = tasks.map(t => (t.id === task.id ? task : t));
    handleUpdate(nextTasks, { type: 'edit', task });
  };

  const renderColumn = (status: TaskStatus) => {
    const columnTasks = tasks.filter(t => t.status === status);
    const isProgress = status === 'inprogress';
    const isDone = status === 'done';

    let bgColor = 'var(--ggui-color-neutral-100)';
    if (isProgress) bgColor = 'var(--ggui-color-primary-50)';
    if (isDone) bgColor = 'var(--ggui-color-success-50)';

    return (
      <Box
        key={status}
        padding={16}
        borderRadius="lg"
        background={bgColor}
        style={{ flex: 1, minWidth: '300px', minHeight: '600px' }}
      >
        <Stack gap={16}>
          <Row justify="between" align="center">
            <Text variant="h3" weight="bold" color="var(--ggui-color-neutral-700)">
              {STATUS_LABELS[status]}
            </Text>
            <Badge variant="default" pill>
              {columnTasks.length.toString()}
            </Badge>
          </Row>

          <Stack gap={12}>
            {columnTasks.map((task, idx) => (
              <div
                key={task.id}
                style={{
                  animation: motionEnabled ? animation.slideInUp : 'none',
                  animationDelay: (idx * 50) + 'ms'
                }}
              >
                <TaskCard
                  task={task}
                  onMove={(newStatus) => moveTask(task, newStatus)}
                  onEdit={editTask}
                />
              </div>
            ))}

            {addingTo === status ? (
              <div style={{ animation: motionEnabled ? animation.scaleIn : 'none' }}>
                <AddTaskForm
                  onAdd={(data) => addTask(status, data)}
                  onCancel={() => setAddingTo(null)}
                />
              </div>
            ) : (
              <Button
                variant="ghost"
                fullWidth
                leftIcon={<Icon name="plus" size={16} />}
                onClick={() => setAddingTo(status)}
              >
                Add Task
              </Button>
            )}
          </Stack>
        </Stack>
      </Box>
    );
  };

  return (
    <Container maxWidth="xl">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Summary Bar */}
        <Card padding={16} shadow="sm">
          <Row justify="between" align="center" wrap>
            <Stack gap={4}>
              <Text variant="h2" weight="bold">{boardTitle}</Text>
              <Text variant="caption" color="var(--ggui-color-neutral-500)">
                Overview of tasks and progress
              </Text>
            </Stack>
            <Row gap={24} align="center">
              <Stack align="center" gap={2}>
                <Text variant="h3" weight="bold">{counts.total.toString()}</Text>
                <Text variant="caption" color="var(--ggui-color-neutral-500)">Total</Text>
              </Stack>
              <Divider orientation="vertical" />
              <Stack align="center" gap={2}>
                <Text variant="h3" weight="bold" color="var(--ggui-color-success-600)">
                  {counts.completed.toString()}
                </Text>
                <Text variant="caption" color="var(--ggui-color-neutral-500)">Completed</Text>
              </Stack>
              <Box paddingX={12} paddingY={4} borderRadius="full" background="var(--ggui-color-primary-100)">
                <Text variant="label" color="var(--ggui-color-primary-700)">
                  {(counts.total > 0 ? Math.round((counts.completed / counts.total) * 100) : 0).toString()}% Done
                </Text>
              </Box>
            </Row>
          </Row>
        </Card>

        {/* Board */}
        <Box style={{ overflowX: 'auto', paddingBottom: '16px' }}>
          <Row gap={24} align="start" style={{ minWidth: '1000px' }}>
            {renderColumn('todo')}
            {renderColumn('inprogress')}
            {renderColumn('done')}
          </Row>
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Button,
  Icon,
  Divider,
  Box,
  Badge,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

/**
 * Interface for element data
 */
export interface ElementData {
  name: string;
  symbol: string;
  number: number;
  atomic_mass: string | number;
  category: string;
  summary: string;
  xpos: number;
  ypos: number;
  shells: number[];
  electron_configuration: string;
  phase: string;
  appearance?: string;
}

export interface Props {
  /** Array of chemical elements */
  elements: ElementData[];
  /** Title for the component */
  title?: string;
}

/**
 * Mapping of chemical categories to design system color tokens
 */
const CATEGORY_COLORS: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
  'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition metal': 'var(--ggui-color-primary-200, #bae6fd)',
  'post-transition metal': 'var(--ggui-color-primary-400, #38bdf8)',
  'metalloid': 'var(--ggui-color-success-500, #22c55e)',
  'diatomic nonmetal': 'var(--ggui-color-success-200, #bbf7d0)',
  'polyatomic nonmetal': 'var(--ggui-color-success-300, #86efac)',
  'noble gas': 'var(--ggui-color-info-500, #06b6d4)',
  'lanthanide': 'var(--ggui-color-primary-100, #e0f2fe)',
  'actinide': 'var(--ggui-color-primary-50, #f0f9ff)',
  'unknown': 'var(--ggui-color-neutral-100, #f3f4f6)',
};

/**
 * Standard categories for the legend
 */
const CATEGORIES = [
  { label: 'Alkali Metal', key: 'alkali metal' },
  { label: 'Alkaline Earth', key: 'alkaline earth metal' },
  { label: 'Transition Metal', key: 'transition metal' },
  { label: 'Post-Transition', key: 'post-transition metal' },
  { label: 'Metalloid', key: 'metalloid' },
  { label: 'Nonmetal', key: 'diatomic nonmetal' },
  { label: 'Noble Gas', key: 'noble gas' },
  { label: 'Lanthanide', key: 'lanthanide' },
  { label: 'Actinide', key: 'actinide' },
];

/**
 * Interactive Periodic Table Component
 * 
 * Features an 18-column grid matching the standard periodic table layout,
 * interactive element cells with category color-coding, a details panel,
 * and search/filter functionality.
 */
export default function PeriodicTable({ 
  elements = [], 
  title = "Periodic Table of Elements" 
}: Props) {
  const [search, setSearch] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);
  const { motionEnabled } = useMotion();

  const filteredElements = useMemo(() => {
    if (!search) return elements;
    const lowerSearch = search.toLowerCase();
    return elements.filter(el => 
      el.name.toLowerCase().includes(lowerSearch) || 
      el.symbol.toLowerCase().includes(lowerSearch) ||
      el.number.toString() === search
    );
  }, [elements, search]);

  const isHighlighted = (el: ElementData) => {
    if (!search) return true;
    return filteredElements.some(f => f.number === el.number);
  };

  const getCategoryColor = (cat: string) => {
    return CATEGORY_COLORS[cat] || CATEGORY_COLORS['unknown'];
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Header Section */}
        <Row justify="between" align="center" wrap>
          <Stack gap={4}>
            <Text variant="h1" weight="bold">{title}</Text>
            <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">
              Interactive chemical data explorer
            </Text>
          </Stack>

          <Box style={{ width: '100%', maxWidth: 400 }}>
            <Input
              label="Search"
              placeholder="e.g. Gold, Au, or 79"
              value={search}
              onChange={setSearch}
              leftIcon={<Icon name="search" size={18} />}
            />
          </Box>
        </Row>

        {/* Legend */}
        <Row gap={12} wrap justify="center" style={{ padding: 'var(--ggui-spacing-2, 8px)' }}>
          {CATEGORIES.map(cat => (
            <Row key={cat.key} gap={8} align="center">
              <div style={{
                width: 16,
                height: 16,
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                backgroundColor: CATEGORY_COLORS[cat.key],
                border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)'
              }} />
              <Text variant="caption" weight="medium">{cat.label}</Text>
            </Row>
          ))}
        </Row>

        {/* Main Grid Layout */}
        <div style={{
          position: 'relative',
          display: 'grid',
          gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
          gap: 'var(--ggui-spacing-1, 4px)',
          padding: 'var(--ggui-spacing-2, 8px)',
          overflowX: 'auto',
          minWidth: 800,
          background: 'var(--ggui-color-neutral-50, #f9fafb)',
          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
          border: '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
          animation: motionEnabled ? animation.fadeIn : 'none'
        }}>
          {elements.map((el) => {
            const active = isHighlighted(el);
            const bgColor = getCategoryColor(el.category);

            return (
              <div
                key={el.number}
                onClick={() => setSelectedElement(el)}
                style={{
                  gridColumn: el.xpos,
                  gridRow: el.ypos,
                  aspectRatio: '1/1',
                  display: 'flex',
                  flexDirection: 'column',
                  padding: 'var(--ggui-spacing-1, 4px)',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                  backgroundColor: active ? bgColor : 'var(--ggui-color-neutral-100, #f3f4f6)',
                  opacity: active ? 1 : 0.3,
                  cursor: 'pointer',
                  border: selectedElement?.number === el.number 
                    ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
                    : '1px solid var(--ggui-color-neutral-200, #e5e7eb)',
                  transition: transition.normal,
                  boxShadow: active ? 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))' : 'none',
                  transform: active && selectedElement?.number === el.number ? 'scale(1.05)' : 'scale(1)',
                  zIndex: selectedElement?.number === el.number ? 10 : 1,
                  position: 'relative'
                }}
              >
                <Text style={{ 
                  fontSize: '9px', 
                  position: 'absolute', 
                  top: 2, 
                  left: 4,
                  fontWeight: 'bold',
                  color: 'rgba(0,0,0,0.6)'
                }}>
                  {el.number}
                </Text>
                <div style={{ 
                  flex: 1, 
                  display: 'flex', 
                  alignItems: 'center', 
                  justifyContent: 'center' 
                }}>
                  <Text weight="bold" style={{ fontSize: 'var(--ggui-font-size-lg, 18px)' }}>
                    {el.symbol}
                  </Text>
                </div>
              </div>
            );
          })}
        </div>

        {/* Detail Panel */}
        {selectedElement && (
          <Card 
            padding={24} 
            shadow="lg"
            style={{ 
              animation: motionEnabled ? animation.slideInUp : 'none',
              borderTopWidth: '4px',
              borderTopStyle: 'solid',
              borderTopColor: getCategoryColor(selectedElement.category)
            }}
          >
            <Stack gap={16}>
              <Row justify="between" align="start">
                <Stack gap={4}>
                  <Row gap={12} align="center">
                    <Text variant="h2" weight="bold">{selectedElement.name}</Text>
                    <Badge variant="primary">{selectedElement.symbol}</Badge>
                    <Text variant="h3" color="var(--ggui-color-neutral-500, #6b7280)">#{selectedElement.number}</Text>
                  </Row>
                  <Text variant="body" weight="medium" color="var(--ggui-color-primary-600, #0284c7)">
                    {selectedElement.category.charAt(0).toUpperCase() + selectedElement.category.slice(1)}
                  </Text>
                </Stack>
                <Button variant="ghost" size="sm" onClick={() => setSelectedElement(null)} leftIcon={<Icon name="x" size={16} />}>
                  Close
                </Button>
              </Row>

              <Divider />

              <div style={{ 
                display: 'grid', 
                gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', 
                gap: 'var(--ggui-spacing-6, 24px)' 
              }}>
                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Physical Properties</Text>
                  <Row justify="between">
                    <Text variant="bodySmall">Atomic Mass</Text>
                    <Text weight="semibold">{selectedElement.atomic_mass} u</Text>
                  </Row>
                  <Row justify="between">
                    <Text variant="bodySmall">Phase</Text>
                    <Text weight="semibold">{selectedElement.phase}</Text>
                  </Row>
                  {selectedElement.appearance && (
                    <Row justify="between">
                      <Text variant="bodySmall">Appearance</Text>
                      <Text weight="semibold" align="right" style={{ maxWidth: 150 }}>{selectedElement.appearance}</Text>
                    </Row>
                  )}
                </Stack>

                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Atomic Structure</Text>
                  <Row justify="between">
                    <Text variant="bodySmall">Electron Configuration</Text>
                    <Text weight="semibold" style={{ fontFamily: 'monospace' }}>{selectedElement.electron_configuration}</Text>
                  </Row>
                  <Row justify="between">
                    <Text variant="bodySmall">Shells</Text>
                    <Text weight="semibold">{selectedElement.shells.join(', ')}</Text>
                  </Row>
                </Stack>

                <Stack gap={8}>
                  <Text variant="label" color="var(--ggui-color-neutral-500, #6b7280)">Summary</Text>
                  <Text variant="bodySmall" style={{ lineHeight: 1.6 }}>
                    {selectedElement.summary}
                  </Text>
                </Stack>
              </div>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Heading,
  Badge,
  Tabs,
  Table,
  Button,
  Icon,
  Box,
  Divider,
  Spacer
} from '@ggui-ai/design/primitives';

interface Review {
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface Specification {
  label: string;
  value: string;
}

interface Props {
  productId: string;
  name?: string;
  price?: number;
  currency?: string;
  rating?: number;
  stock?: number;
  description?: string;
  specifications?: Specification[];
  reviews?: Review[];
  onAddToCart?: (data: { productId: string; quantity: number }) => void;
}

export default function ProductDetailPage({
  productId = 'p-123',
  name = 'Premium Wireless Headphones',
  price = 299.99,
  currency = '$',
  rating = 4.5,
  stock = 12,
  description = 'Experience crystal clear audio with our premium wireless headphones. Featuring active noise cancellation and 30-hour battery life.',
  specifications = [
    { label: 'Driver Size', value: '40mm' },
    { label: 'Battery Life', value: '30 hours' },
    { label: 'Connectivity', value: 'Bluetooth 5.0' },
    { label: 'Weight', value: '250g' }
  ],
  reviews = [
    { author: 'Jane Doe', rating: 5, text: 'Amazing sound quality!', date: '2023-10-01' },
    { author: 'John Smith', rating: 4, text: 'Very comfortable for long sessions.', date: '2023-09-28' }
  ],
  onAddToCart
}: Props) {
  const [quantity, setQuantity] = useState(1);

  const increment = () => {
    if (quantity < stock) setQuantity(prev => prev + 1);
  };

  const decrement = () => {
    if (quantity > 1) setQuantity(prev => prev - 1);
  };

  const handleAddToCart = () => {
    if (onAddToCart) {
      onAddToCart({ productId, quantity });
    }
  };

  // Star SVG helper - using children in Icon primitive
  const renderStars = (count: number) => {
    return (
      <Row gap={2}>
        {[1, 2, 3, 4, 5].map((star) => (
          <Icon
            key={star}
            size={16}
            color={star <= count ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-neutral-300)'}
          >
            <path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z" />
          </Icon>
        ))}
      </Row>
    );
  };

  const getStockBadge = () => {
    if (stock === 0) return <Badge variant="error">Out of Stock</Badge>;
    if (stock <= 5) return <Badge variant="warning">Low Stock</Badge>;
    return <Badge variant="success">In Stock</Badge>;
  };

  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Box paddingY={16}>
          <Text variant="body" color="var(--ggui-color-neutral-700)">
            {description}
          </Text>
        </Box>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Box paddingY={16}>
          <Table
            columns={[
              { key: 'label', header: 'Feature', width: '40%' },
              { key: 'value', header: 'Detail' },
            ]}
            data={specifications}
            bordered
          />
        </Box>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack direction="vertical" gap={16} paddingY={16}>
          {reviews.map((review, index) => (
            <Card key={index} padding={16} shadow="none">
              <Stack gap={8}>
                <Row justify="between" align="center">
                  <Text weight="bold">{review.author}</Text>
                  <Text variant="caption" color="var(--ggui-color-neutral-500)">{review.date}</Text>
                </Row>
                {renderStars(review.rating)}
                <Text variant="body" color="var(--ggui-color-neutral-700)">{review.text}</Text>
              </Stack>
            </Card>
          ))}
          {reviews.length === 0 && (
            <Text align="center" color="var(--ggui-color-neutral-500)" padding={24}>No reviews yet.</Text>
          )}
        </Stack>
      ),
    },
  ];

  const truncatedDescription = description.length > 200 ? description.substring(0, 200) + "..." : description;
  const formattedPrice = price.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  const stockText = stock > 0 ? stock + " in stock" : "Out of stock";

  return (
    <Container padding={24} maxWidth="xl">
      <Stack gap={32}>
        {/* Top Section: Responsive via flex wrap on Row */}
        <Row gap={32} wrap align="start">
          {/* Product Image Placeholder */}
          <Box
            style={{
              flex: '1 1 400px',
              minHeight: 400,
              backgroundColor: 'var(--ggui-color-primary-50)',
              border: '1px solid var(--ggui-color-primary-200)',
              borderRadius: 'var(--ggui-shape-radius-lg)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              overflow: 'hidden'
            }}
          >
            <Stack align="center" gap={12}>
              <div style={{
                width: 80,
                height: 80,
                borderRadius: 'var(--ggui-shape-radius-full)',
                backgroundColor: 'var(--ggui-color-primary-100)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center'
              }}>
                <Icon name="search" size={40} color="var(--ggui-color-primary-600)" />
              </div>
              <Text variant="h3" weight="bold" color="var(--ggui-color-primary-700)" align="center">
                {name}
              </Text>
              <Text variant="caption" color="var(--ggui-color-primary-400)">Product Preview</Text>
            </Stack>
          </Box>

          {/* Product Purchasing Info */}
          <Stack gap={24} style={{ flex: '1 1 350px' }}>
            <Stack gap={12}>
              <Heading level={1}>{name}</Heading>
              <Row gap={16} align="center">
                <Row gap={4} align="center">
                  {renderStars(Math.round(rating))}
                  <Text weight="semibold" color="var(--ggui-color-warning-600)">{rating}</Text>
                </Row>
                <Divider orientation="vertical" margin={0} />
                {getStockBadge()}
              </Row>
            </Stack>

            <Text
              variant="h1"
              weight="bold"
              color="var(--ggui-color-primary-600)"
            >
              {currency}{formattedPrice}
            </Text>

            <Divider />

            <Text variant="body" color="var(--ggui-color-neutral-600)">
              {truncatedDescription}
            </Text>

            <Spacer size={12} />

            {/* Quantity and CTA */}
            <Stack gap={20}>
              <Row gap={16} align="center">
                <Text weight="medium">Quantity</Text>
                <Row gap={0} style={{ 
                  border: '1px solid var(--ggui-color-neutral-300)', 
                  borderRadius: 'var(--ggui-shape-radius-md)', 
                  overflow: 'hidden',
                  backgroundColor: 'var(--ggui-color-neutral-50)'
                }}>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={decrement}
                    disabled={quantity <= 1 || stock === 0}
                    leftIcon={<Icon name="minus" size={12} />}
                  />
                  <Box paddingX={16} style={{ 
                    display: 'flex', 
                    alignItems: 'center', 
                    justifyContent: 'center', 
                    minWidth: 48,
                    borderLeft: '1px solid var(--ggui-color-neutral-200)',
                    borderRight: '1px solid var(--ggui-color-neutral-200)'
                  }}>
                    <Text weight="bold">{quantity}</Text>
                  </Box>
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={increment}
                    disabled={quantity >= stock || stock === 0}
                    leftIcon={<Icon name="plus" size={12} />}
                  />
                </Row>
                <Text variant="caption" color="var(--ggui-color-neutral-500)">
                  {stockText}
                </Text>
              </Row>

              <Button
                variant="primary"
                size="lg"
                fullWidth
                disabled={stock === 0}
                onClick={handleAddToCart}
                leftIcon={<Icon name="check" size={20} />}
              >
                {stock === 0 ? 'Currently Unavailable' : 'Add to Cart'}
              </Button>
            </Stack>
          </Stack>
        </Row>

        {/* Tabs for Details */}
        <Card padding={0} shadow="sm">
          <Tabs items={tabItems} variant="line" fullWidth />
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Input,
  Button,
  Badge,
  Box,
  Icon,
  MotionKeyframes,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Message {
  sender: string;
  senderId: string;
  text: string;
  timestamp: string;
}

interface User {
  id: string;
  name: string;
}

interface Props {
  /** The title of the chat conversation */
  title?: string;
  /** Number of people currently in the chat */
  participantCount?: number;
  /** The current logged in user */
  currentUser: User;
  /** Initial list of messages to display */
  initialMessages?: Message[];
  /** Callback fired when the user sends a message */
  onSend: (data: { text: string; timestamp: string }) => void;
}

/**
 * Real-time chat interface component.
 */
export default function GeneratedComponent({
  title = 'Team Chat',
  participantCount = 0,
  currentUser = { id: 'user-1', name: 'Anonymous' },
  initialMessages = [],
  onSend,
}: Props) {
  const [messages, setMessages] = useState<Message[]>(initialMessages);
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<Record<string, number>>({});
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to latest message
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, typingUsers]);

  // Handle incoming data from the agent
  useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (!data) return;

      if (data.type === 'message') {
        const msg: Message = {
          sender: data.sender || 'Unknown',
          senderId: data.senderId || 'unknown',
          text: data.text || '',
          timestamp: data.timestamp || new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        };
        setMessages((prev) => [...prev, msg]);
      } else if (data.type === 'typing') {
        setTypingUsers((prev) => ({
          ...prev,
          [data.sender]: Date.now(),
        }));
      }
    };

    // Use global addEventListener to catch events from the ggui environment
    addEventListener('ggui:agent-data' as any, handleAgentData);

    // Clear typing states older than 3 seconds
    const interval = setInterval(() => {
      const now = Date.now();
      setTypingUsers((prev) => {
        const next = { ...prev };
        let hasChanges = false;
        Object.keys(next).forEach((key) => {
          if (now - next[key] > 3000) {
            delete next[key];
            hasChanges = true;
          }
        });
        return hasChanges ? next : prev;
      });
    }, 1000);

    return () => {
      removeEventListener('ggui:agent-data' as any, handleAgentData);
      clearInterval(interval);
    };
  }, []);

  const handleSend = () => {
    if (!inputValue.trim()) return;

    const time = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    const msg: Message = {
      sender: currentUser.name,
      senderId: currentUser.id,
      text: inputValue,
      timestamp: time,
    };

    setMessages((prev) => [...prev, msg]);
    onSend?.({ text: inputValue, timestamp: time });
    setInputValue('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      handleSend();
    }
  };

  const activeTyping = Object.keys(typingUsers);

  return (
    <Card 
      padding={0} 
      shadow="lg" 
      border 
      style={{ 
        height: '600px', 
        display: 'flex', 
        flexDirection: 'column', 
        overflow: 'hidden',
        backgroundColor: 'var(--ggui-color-neutral-50)'
      }}
    >
      <MotionKeyframes />

      {/* Conversation Header */}
      <Box 
        padding="var(--ggui-spacing-4)" 
        background="var(--ggui-color-primary-50)" 
        style={{ borderBottom: '1px solid var(--ggui-color-primary-100)' }}
      >
        <Row justify="between" align="center">
          <Stack gap={2}>
            <Text weight="bold" variant="h3" color="var(--ggui-color-primary-900)">
              {title}
            </Text>
            <Row gap={6} align="center">
              <Badge variant="success" size="sm">Online</Badge>
              <Text variant="caption" color="var(--ggui-color-primary-700)">
                {participantCount} participants
              </Text>
            </Row>
          </Stack>
          <Button variant="ghost" size="sm">
            <Icon name="settings" size={18} color="var(--ggui-color-primary-600)" />
          </Button>
        </Row>
      </Box>

      {/* Message History */}
      <Box 
        ref={scrollRef}
        style={{ 
          flex: 1, 
          overflowY: 'auto', 
          padding: 'var(--ggui-spacing-4)',
          backgroundColor: '#ffffff',
          scrollBehavior: 'smooth'
        }}
      >
        <Stack gap={16}>
          {messages.map((m, i) => {
            const isMe = m.senderId === currentUser.id;
            return (
              <Box 
                key={m.senderId + '-' + i}
                style={{
                  alignSelf: isMe ? 'flex-end' : 'flex-start',
                  maxWidth: '85%',
                  animation: animation.fadeIn
                }}
              >
                <Stack gap={4} align={isMe ? 'end' : 'start'}>
                  <Text variant="caption" color="var(--ggui-color-neutral-500)">
                    {isMe ? 'You' : m.sender} • {m.timestamp}
                  </Text>
                  <Box
                    padding="var(--ggui-spacing-2) var(--ggui-spacing-4)"
                    borderRadius="var(--ggui-shape-radius-lg)"
                    style={{
                      backgroundColor: isMe ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-neutral-100)',
                      color: isMe ? 'white' : 'var(--ggui-color-neutral-900)',
                      borderTopRightRadius: isMe ? '2px' : '12px',
                      borderTopLeftRadius: !isMe ? '2px' : '12px',
                      boxShadow: 'var(--ggui-shape-shadow-sm)',
                    }}
                  >
                    <Text>{m.text}</Text>
                  </Box>
                </Stack>
              </Box>
            );
          })}
        </Stack>
      </Box>

      {/* Input Section */}
      <Box 
        padding="var(--ggui-spacing-4)" 
        background="white" 
        style={{ borderTop: '1px solid var(--ggui-color-neutral-200)' }}
      >
        <Stack gap={8}>
          {activeTyping.length > 0 && (
            <Box style={{ animation: animation.fadeIn }}>
              <Text variant="caption" color="var(--ggui-color-neutral-500)">
                <Stack direction="horizontal" gap={4} align="center">
                   <div style={{ display: 'flex', gap: 2 }}>
                      <span style={{ animation: 'ggui-fadeIn 0.8s infinite alternate' }}>•</span>
                      <span style={{ animation: 'ggui-fadeIn 0.8s infinite alternate 0.2s' }}>•</span>
                      <span style={{ animation: 'ggui-fadeIn 0.8s infinite alternate 0.4s' }}>•</span>
                   </div>
                   {activeTyping.length === 1 
                     ? activeTyping[0] + ' is typing...' 
                     : activeTyping.length + ' people are typing...'}
                </Stack>
              </Text>
            </Box>
          )}

          <Row gap={8} align="end">
            <Box style={{ flex: 1 }} onKeyDown={handleKeyDown}>
              <Input
                label="Message Content"
                placeholder="Send a message..."
                value={inputValue}
                onChange={setInputValue}
              />
            </Box>
            <Button 
              variant="primary" 
              onClick={handleSend} 
              disabled={!inputValue.trim()}
              rightIcon={<Icon name="chevron-right" size={16} />}
            >
              Send
            </Button>
          </Row>
        </Stack>
      </Box>
    </Card>
  );
}

