import { useState } from 'react';
import { Container, Card, Stack, Text, Input, TextArea, Button, RadioGroup, Checkbox, Divider, Row } from '@ggui-ai/design/primitives';

interface Feature {
  id: string;
  label: string;
}

interface Props {
  ratingLabels: string[]; // Length should be 5
  features: Feature[];
  onSubmit: (data: any) => void;
}

export default function MultiStepSurvey({ ratingLabels, features, onSubmit }: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    rating: '',
    selectedFeatures: [] as string[],
    comments: ''
  });
  const [errors, setErrors] = useState({ name: '', email: '' });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStepValid = () => {
    if (step === 1) return formData.name.trim() !== '' && validateEmail(formData.email);
    if (step === 2) return formData.rating !== '';
    return true;
  };

  const handleNext = () => setStep(prev => Math.min(prev + 1, 5));
  const handleBack = () => setStep(prev => Math.max(prev - 1, 1));

  const updateFormData = (key: string, value: any) => setFormData(prev => ({ ...prev, [key]: value }));

  const toggleFeature = (featureId: string, checked: boolean) => {
    updateFormData('selectedFeatures', checked
      ? [...formData.selectedFeatures, featureId]
      : formData.selectedFeatures.filter(id => id !== featureId));
  };

  const renderStep = () => {
    switch (step) {
      case 1:
        return (
          <Stack gap={16}>
            <Input label="Name" value={formData.name} onChange={(v) => { updateFormData('name', v); setErrors({ ...errors, name: v.trim() === '' ? 'Required' : '' }); }} required error={errors.name} />
            <Input label="Email" value={formData.email} onChange={(v) => { updateFormData('email', v); setErrors({ ...errors, email: !validateEmail(v) ? 'Invalid email' : '' }); }} required error={errors.email} />
          </Stack>
        );
      case 2:
        return (
          <RadioGroup 
            label="How satisfied are you?" 
            value={formData.rating} 
            onChange={(v) => updateFormData('rating', v)} 
            options={[1, 2, 3, 4, 5].map(r => ({ value: String(r), label: ratingLabels[r-1] || String(r) }))} 
          />
        );
      case 3:
        return (
          <Stack gap={8}>
            <Text variant="label">Which features interest you?</Text>
            {features.map(f => (
              <Checkbox key={f.id} label={f.label} checked={formData.selectedFeatures.includes(f.id)} onChange={(c) => toggleFeature(f.id, c)} />
            ))}
          </Stack>
        );
      case 4:
        return (
          <Stack gap={8}>
            <TextArea label="Additional Comments" value={formData.comments} onChange={(v) => updateFormData('comments', v)} maxLength={500} />
            <Text variant="caption" align="right">{formData.comments.length} / 500 characters</Text>
          </Stack>
        );
      case 5:
        return (
          <Stack gap={12}>
            <Text variant="h3">Review your answers</Text>
            <Text>Name: {formData.name}</Text>
            <Text>Email: {formData.email}</Text>
            <Text>Rating: {formData.rating}</Text>
            <Text>Features: {formData.selectedFeatures.length > 0 ? formData.selectedFeatures.join(', ') : 'None'}</Text>
            <Text>Comments: {formData.comments || 'No comments'}</Text>
          </Stack>
        );
    }
  };

  return (
    <Container maxWidth="sm">
      <Card padding={24}>
        <Stack gap={24} role="form" aria-label="Survey Form">
          <Text variant="h2">Step {step} of 5</Text>
          {renderStep()}
          <Row justify="between">
            <Button disabled={step === 1} onClick={handleBack}>Back</Button>
            {step < 5 ? (
              <Button variant="primary" disabled={!isStepValid()} onClick={handleNext}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onSubmit(formData)}>Submit</Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Container, Card, Stack, Row, Text, Button, Input, 
  Select, Badge, Divider 
} from '@ggui-ai/design/primitives';

interface Task {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee: string;
  dueDate: string;
  column: 'todo' | 'inprogress' | 'done';
}

interface Props {
  initialTasks: Task[];
  onTaskUpdate: (task: Task) => void;
}

export default function KanbanBoard({ initialTasks, onTaskUpdate }: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<Task['priority']>('medium');

  const updateTask = (updatedTask: Task) => {
    setTasks(prev => prev.map(t => t.id === updatedTask.id ? updatedTask : t));
    onTaskUpdate(updatedTask);
  };

  const addTask = (column: Task['column']) => {
    if (!newTaskTitle) return;
    const newTask: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: 'Unassigned',
      dueDate: new Date().toISOString().split('T')[0],
      column,
    };
    setTasks(prev => [...prev, newTask]);
    onTaskUpdate(newTask);
    setNewTaskTitle('');
    setAddingTo(null);
  };

  const columns: { id: Task['column']; label: string }[] = [
    { id: 'todo', label: 'To Do' },
    { id: 'inprogress', label: 'In Progress' },
    { id: 'done', label: 'Done' },
  ];

  const totalTasks = tasks.length;
  const completedCount = tasks.filter(t => t.column === 'done').length;

  return (
    <Container maxWidth="xl">
      <Stack gap={24}>
        <Card padding={16}>
          <Row justify="between" align="center">
            <Text variant="h2">Project Board</Text>
            <Text>Total: {totalTasks} | Completed: {completedCount}</Text>
          </Row>
        </Card>

        <Row gap={16} align="start" wrap={true}>
          {columns.map(col => (
            <Stack key={col.id} style={{ flex: 1, minWidth: '300px' }}>
              <Card padding={16} border={true}>
                <Row justify="between" align="center">
                  <Text variant="h3">{col.label}</Text>
                  <Badge variant="secondary">{tasks.filter(t => t.column === col.id).length}</Badge>
                </Row>
                <Divider margin={16} />
                <Stack gap={12}>
                  {tasks.filter(t => t.column === col.id).map(task => (
                    <Card key={task.id} padding={12} shadow="sm">
                      <Stack gap={8}>
                        <Text weight="medium">{task.title}</Text>
                        <Row justify="between" align="center">
                          <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'success'}>
                            {task.priority}
                          </Badge>
                          <Text variant="caption">{task.dueDate}</Text>
                        </Row>
                        <Select
                          label="Status"
                          value={task.column}
                          onChange={(val) => updateTask({ ...task, column: val as any })}
                          options={columns.map(c => ({ value: c.id, label: c.label }))}
                        />
                      </Stack>
                    </Card>
                  ))}
                  {addingTo === col.id ? (
                    <Stack gap={8}>
                      <Input label="Task Title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="New task title" />
                      <Select 
                        label="Priority"
                        value={newTaskPriority} 
                        onChange={(v) => setNewTaskPriority(v as any)}
                        options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]}
                      />
                      <Button onClick={() => addTask(col.id)} variant="primary">Save</Button>
                      <Button onClick={() => setAddingTo(null)} variant="ghost">Cancel</Button>
                    </Stack>
                  ) : (
                    <Button onClick={() => setAddingTo(col.id)} variant="outline">
                      Add Task
                    </Button>
                  )}
                </Stack>
              </Card>
            </Stack>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

