  group: number;
  period: number;
  config: string;
}

interface Props {
  elements: Element[];
}

const CATEGORY_COLORS: Record<string, string> = {
  'Alkali Metal': 'var(--ggui-color-primary-300)',
  'Alkaline Earth Metal': 'var(--ggui-color-primary-200)',
  'Transition Metal': 'var(--ggui-color-warning-300)',
  'Post-transition Metal': 'var(--ggui-color-neutral-300)',
