  'Nonmetal': 'var(--ggui-color-success-300)',
  'Halogen': 'var(--ggui-color-error-200)',
  'Noble Gas': 'var(--ggui-color-primary-400)',
  'Lanthanide': 'var(--ggui-color-warning-200)',
  'Actinide': 'var(--ggui-color-error-300)',
};

export default function PeriodicTable({ elements }: Props) {
  const [filter, setFilter] = useState('');
  const [selected, setSelected] = useState<Element | null>(null);

  const filteredElements = elements.filter(
    (e) =>
      e.name.toLowerCase().includes(filter.toLowerCase()) ||
      e.symbol.toLowerCase().includes(filter.toLowerCase())
  );

  return (
    <Container maxWidth="xl">
      <Stack gap={24}>
        <Input
          label="Search Elements"
          placeholder="e.g. Hydrogen or H"
          value={filter}
          onChange={setFilter}
        />

        <Box style={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(18, 1fr)', 
          gap: 'var(--ggui-spacing-1)',
          padding: 'var(--ggui-spacing-4)',
          border: '1px solid var(--ggui-color-neutral-200)',
          borderRadius: 'var(--ggui-shape-radius-md)'
        }}>
          {elements.map((el) => {
            const isVisible = filteredElements.includes(el);
            return (
              <Box
                key={el.number}
                style={{
                  gridColumn: el.group,
                  gridRow: el.period,
                  opacity: isVisible ? 1 : 0.1,
                  transition: 'opacity 0.2s',
                  cursor: isVisible ? 'pointer' : 'default',
                  backgroundColor: CATEGORY_COLORS[el.category] || 'var(--ggui-color-neutral-200)',
                  padding: 'var(--ggui-spacing-1)',
                  borderRadius: 'var(--ggui-shape-radius-sm)',
                  border: selected?.number === el.number ? '2px solid var(--ggui-color-primary-700)' : 'none',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center'
                }}
                onClick={() => isVisible && setSelected(el)}
              >
                <Text variant="caption">{el.number}</Text>
                <Text weight="bold">{el.symbol}</Text>
              </Box>
            );
          })}
        </Box>

        {selected && (
          <Card>
            <Stack gap={8}>
              <Text variant="h3">{selected.name} ({selected.symbol})</Text>
              <Text>Atomic Number: {selected.number}</Text>
              <Text>Atomic Weight: {selected.weight}</Text>
              <Text>Category: {selected.category}</Text>
              <Text>Configuration: {selected.config}</Text>
              <Button onClick={() => setSelected(null)}>Close</Button>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Container, Card, Stack, Row, Text, Button, Badge, 
  Tabs, Table, Icon 
} from '@ggui-ai/design/primitives';

interface Review {
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface Props {
  productId?: string;
  title?: string;
  price?: number;
  currency?: string;
  rating?: number;
  stock?: number;
  description?: string;
  specifications?: { [key: string]: string };
  reviews?: Review[];
  onAddToCart?: (data: { productId: string; quantity: number }) => void;
}

export default function ProductDetailPage({
  productId = '1',
  title = 'Sample Product',
  price = 99.99,
  currency = '$',
  rating = 4,
  stock = 10,
  description = 'Detailed product description goes here.',
  specifications = { 'Color': 'Blue', 'Size': 'Large', 'Material': 'Cotton' },
  reviews = [{ author: 'John Doe', rating: 5, text: 'Great product!', date: '2023-10-01' }],
  onAddToCart = () => {}
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const isOutOfStock = stock <= 0;
  const isLowStock = stock > 0 && stock <= 5;

  const renderStars = (rating: number) => (
    <Row gap={4}>
      {[...Array(5)].map((_, i) => (
        <Icon 
          key={i} 
          name={i < rating ? 'check' : 'minus'} 
          size={16} 
          color={i < rating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-neutral-300)'} 
        />
      ))}
    </Row>
  );

  return (
    <Container padding={24}>
      <Stack gap={24}>
        {/* Top Section */}
        <Stack direction="horizontal" gap={32} style={{ flexWrap: 'wrap' }}>
          <Card padding={0} style={{ width: '100%', maxWidth: 400, aspectRatio: '1/1', background: 'var(--ggui-color-primary-100)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Text variant="h2">{title}</Text>
          </Card>

          <Stack gap={16} style={{ flex: 1, minWidth: 300 }}>
            <Text variant="h1">{title}</Text>
            <Text variant="h2">{currency}{price.toFixed(2)}</Text>
            {renderStars(rating)}

            {isOutOfStock ? (
              <Badge variant="error">Out of Stock</Badge>
            ) : isLowStock ? (
              <Badge variant="warning">Low Stock ({stock} left)</Badge>
            ) : (
              <Badge variant="success">In Stock</Badge>
            )}
          </Stack>
        </Stack>

        {/* Tabs Section */}
        <Tabs
          activeKey={activeTab}
          onChange={setActiveTab}
          items={[
            {
              key: 'description',
              label: 'Description',
              content: <Text>{description}</Text>
            },
            {
              key: 'specifications',
              label: 'Specifications',
              content: (
                <Table
                  columns={[
                    { key: 'key', header: 'Property' },
                    { key: 'value', header: 'Value' }
                  ]}
                  data={Object.entries(specifications).map(([key, value]) => ({ key, value }))}
                />
              )
            },
            {
              key: 'reviews',
              label: 'Reviews',
              content: (
                <Stack gap={16}>
                  {reviews.map((r, i) => (
                    <Card key={i}>
                      <Stack gap={4}>
                        <Row justify="between">
                          <Text weight="bold">{r.author}</Text>
                          <Text variant="caption">{r.date}</Text>
                        </Row>
                        {renderStars(r.rating)}
                        <Text>{r.text}</Text>
                      </Stack>
                    </Card>
                  ))}
                </Stack>
              )
            }
          ]}
        />

        {/* Bottom Section */}
        <Card padding={16}>
          <Row align="center" gap={16}>
            <Row align="center" gap={8}>
              <Button 
                variant="outline" 
                size="sm" 
                onClick={() => setQuantity(Math.max(1, quantity - 1))}
              >-</Button>
              <Text>{quantity}</Text>
              <Button 
                variant="outline" 
                size="sm" 
                onClick={() => setQuantity(Math.min(stock, quantity + 1))}
              >+</Button>
            </Row>

            <Button 
              variant="primary" 
              disabled={isOutOfStock}
              onClick={() => onAddToCart({ productId, quantity })}
            >
              Add to Cart
            </Button>
          </Row>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Input, Button, Row, Box } from '@ggui-ai/design/primitives';

interface Message {
  type: 'message';
  sender: string;
  text: string;
  timestamp: string;
}

interface Typing {
  type: 'typing';
  sender: string;
}

type ChatEvent = Message | Typing;

interface Props {
  title: string;
  participantCount: number;
  userId: string;
  onSend: (data: { text: string; timestamp: string }) => void;
  // External data hook
  onRegisterEvent?: (cb: (data: ChatEvent) => void) => () => void;
}

export default function ChatInterface({ title, participantCount, userId, onSend, onRegisterEvent }: Props) {
  const [messages, setMessages] = useState<Message[]>([]);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const [inputText, setInputText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (onRegisterEvent) {
      return onRegisterEvent((data) => {
        if (data.type === 'message') {
          setMessages((prev) => [...prev, data]);
          setTypingUsers((prev) => {
            const next = new Set(prev);
            next.delete(data.sender);
            return next;
          });
        } else if (data.type === 'typing') {
          setTypingUsers((prev) => new Set(prev).add(data.sender));
          setTimeout(() => {
            setTypingUsers((prev) => {
              const next = new Set(prev);
              next.delete(data.sender);
              return next;
            });
          }, 3000);
        }
      });
    }
  }, [onRegisterEvent]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, typingUsers]);

  const handleSend = () => {
    if (!inputText.trim()) return;
    onSend({ text: inputText, timestamp: new Date().toISOString() });
    setInputText('');
  };

  return (
    <Card padding={0}>
      <Box padding={16} style={{ borderBottom: '1px solid var(--ggui-color-neutral-200)' }}>
        <Stack gap={4}>
          <Text variant="h3">{title}</Text>
          <Text variant="caption" color="var(--ggui-color-neutral-500)">
            {participantCount} participants
          </Text>
        </Stack>
      </Box>

      <Box ref={scrollRef} style={{ height: 400, overflowY: 'auto', padding: 16 }}>
        <Stack gap={16}>
          {messages.map((msg, i) => {
            const isMe = msg.sender === userId;
            return (
              <Row key={i} justify={isMe ? 'end' : 'start'}>
                <Box
                  padding={12}
                  style={{
                    maxWidth: '70%',
                    borderRadius: 'var(--ggui-shape-radius-md)',
                    background: isMe ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-neutral-200)',
                    color: isMe ? 'white' : 'var(--ggui-color-neutral-900)',
                  }}
                >
                  <Text variant="caption" weight="bold">{msg.sender}</Text>
                  <Text>{msg.text}</Text>
                  <Text variant="caption" style={{ opacity: 0.7 }}>
                    {new Date(msg.timestamp).toLocaleTimeString()}
                  </Text>
                </Box>
              </Row>
            );
          })}
          {Array.from(typingUsers).map((user) => (
            <Text key={user} variant="caption" color="var(--ggui-color-neutral-500)">
              {user} is typing...
            </Text>
          ))}
        </Stack>
      </Box>

      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-neutral-200)' }}>
        <Row gap={8}>
          <Input
            label="Message Input"
            value={inputText}
            onChange={setInputText}
            placeholder="Type a message..."
          />
          <Button onClick={handleSend} disabled={!inputText.trim()}>
            Send
          </Button>
        </Row>
      </Box>
    </Card>
  );
}
